import { DEBUG_CHATBOT } from '@/features/ai/agent-runtime/core/config';
import {
  buildBranchStepsFromAlternatives,
  buildPlanStepsFromSpecs,
  flattenPlanHierarchy,
  normalizePlanHierarchy,
  normalizePlannerMeta,
  normalizeStringList,
  parsePlanJson,
} from '@/features/ai/agent-runtime/planning/utils';
import { getAgentAuditLogDelegate } from '@/features/ai/agent-runtime/store-delegates';
import type { LoopSignal, PlanStep, PlannerMeta } from '@/shared/contracts/agent-runtime';
import { runBrainChatCompletion } from '@/shared/lib/ai-brain/server-runtime-client';
import { ErrorSystem } from '@/shared/utils/observability/error-system';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


type PlanStepSpecInput = {
  title?: string;
  tool?: string;
  expectedObservation?: string | null;
  successCriteria?: string | null;
  phase?: string | null;
  priority?: number | null;
  dependsOn?: number[] | string[] | null;
  goalId?: string | null;
  subgoalId?: string | null;
};

const normalizePlanStepSpecs = (steps: PlanStepSpecInput[]): PlanStepSpecInput[] =>
  steps.map((step: PlanStepSpecInput) => {
    const { expectedObservation, successCriteria, phase, priority, dependsOn, ...rest } = step;
    return {
      ...rest,
      ...(expectedObservation != null && { expectedObservation }),
      ...(successCriteria != null && { successCriteria }),
      ...(phase != null && { phase }),
      ...(priority != null && { priority }),
      ...(dependsOn != null && { dependsOn }),
    };
  });

const runLoopGuardTask = async (input: {
  model: string;
  systemPrompt: string;
  userContent: string;
  temperature?: number;
}): Promise<string> => {
  const response = await runBrainChatCompletion({
    modelId: input.model,
    temperature: input.temperature ?? 0.2,
    jsonMode: true,
    messages: [
      {
        role: 'system',
        content: input.systemPrompt,
      },
      {
        role: 'user',
        content: input.userContent,
      },
    ],
  });
  return response.text.trim();
};

export const detectLoopPattern = (
  recent: Array<{
    title: string;
    status: PlanStep['status'];
    tool?: string | null;
    url: string | null;
  }>
): LoopSignal | null => {
  if (recent.length < 3) return null;
  const lastThree = recent.slice(-3);
  const lastFour = recent.slice(-4);
  const titlesThree = lastThree.map((item: { title: string }) => item.title);
  const titlesFour = lastFour.map((item: { title: string }) => item.title);
  const urlsThree = lastThree.map((item: { url: string | null }) => item.url);
  const statusesThree = lastThree.map((item: { status: PlanStep['status'] }) => item.status);
  const sameTitle = new Set(titlesThree.map((title: string) => title.toLowerCase())).size === 1;
  if (sameTitle) {
    return {
      reason: 'Repeated the same step multiple times.',
      pattern: 'repeat-same-step',
      titles: titlesThree,
      urls: urlsThree,
      statuses: statusesThree,
    };
  }
  if (lastFour.length === 4) {
    const [a, b, c, d] = titlesFour.map((title: string) => title.toLowerCase());
    if (a === c && b === d && a !== b) {
      return {
        reason: 'Alternating between the same two steps.',
        pattern: 'alternate-two-steps',
        titles: titlesFour,
        urls: lastFour.map((item: { url: string | null }) => item.url),
        statuses: lastFour.map((item: { status: PlanStep['status'] }) => item.status),
      };
    }
  }
  const stableUrl =
    urlsThree[0] &&
    urlsThree.every((url: string | null) => url && url === urlsThree[0]) &&
    statusesThree.filter((status: PlanStep['status']) => status === 'failed').length >= 2;
  if (stableUrl) {
    return {
      reason: 'Repeated failures on the same URL.',
      pattern: 'same-url-failures',
      titles: titlesThree,
      urls: urlsThree,
      statuses: statusesThree,
    };
  }
  return null;
};

export async function buildLoopGuardReview({
  prompt,
  memory,
  model,
  browserContext,
  currentPlan,
  completedIndex,
  loopSignal,
  lastError,
  runId,
  maxSteps,
  maxStepAttempts,
}: {
  prompt: string;
  memory: string[];
  model: string;
  browserContext?: {
    url: string;
    title: string | null;
    domTextSample: string;
    logs: { level: string; message: string }[];
    uiInventory?: unknown;
  } | null;
  currentPlan: PlanStep[];
  completedIndex: number;
  loopSignal: LoopSignal;
  lastError?: string | null;
  runId?: string;
  maxSteps: number;
  maxStepAttempts: number;
}): Promise<{
  action: 'continue' | 'replan' | 'wait_human';
  reason?: string;
  questions?: string[];
  evidence?: string[];
  steps: PlanStep[];
  hierarchy?: ReturnType<typeof normalizePlanHierarchy> | null;
  meta?: PlannerMeta | null;
}> {
  try {
    const content = await runLoopGuardTask({
      model,
      systemPrompt:
        'You are a loop-guard. Output only JSON with keys: action, reason, questions, evidence, goals, critique, alternatives, taskType, summary, constraints, successSignals. action is \'continue\', \'replan\', or \'wait_human\'. Provide 2-4 questions that test whether the agent is looping. If action is \'replan\', include goals (planner schema) or steps: array of {title, tool, expectedObservation, successCriteria, phase, priority, dependsOn}.',
      userContent: JSON.stringify({
        prompt,
        memory,
        browserContext,
        lastError,
        loopSignal,
        completedStepIndex: completedIndex,
        currentPlan: currentPlan.map((step: PlanStep) => ({
          title: step.title,
          status: step.status,
          tool: step.tool,
          expectedObservation: step.expectedObservation,
          successCriteria: step.successCriteria,
        })),
        maxSteps,
      }),
    });
    const parsed = parsePlanJson(content) as {
      action?: string;
      reason?: string;
      questions?: string[];
      evidence?: string[];
      steps?: Array<{
        title?: string;
        tool?: string;
        expectedObservation?: string;
        successCriteria?: string;
        phase?: string;
        priority?: number;
        dependsOn?: number[] | string[];
      }>;
      goals?: Array<{
        title?: string;
        successCriteria?: string;
        subgoals?: Array<{
          title?: string;
          successCriteria?: string;
          steps?: Array<{
            title?: string;
            tool?: string;
            expectedObservation?: string;
            successCriteria?: string;
            phase?: string;
            priority?: number;
            dependsOn?: number[] | string[];
          }>;
        }>;
      }>;
      taskType?: string;
    } | null;
    if (!parsed) return { action: 'continue', steps: [] };
    const action =
      parsed.action === 'replan' || parsed.action === 'wait_human' ? parsed.action : 'continue';
    const meta = normalizePlannerMeta(parsed);
    const hierarchy = normalizePlanHierarchy(parsed);
    const hierarchySteps = hierarchy ? flattenPlanHierarchy(hierarchy) : [];
    const stepSpecs = hierarchySteps.length > 0 ? hierarchySteps : (parsed.steps ?? []);
    let steps =
      action === 'replan'
        ? buildPlanStepsFromSpecs(
          normalizePlanStepSpecs(stepSpecs),
          meta,
          true,
          maxStepAttempts
        ).slice(0, maxSteps)
        : [];
    if (action === 'replan' && steps.length === 0) {
      const fallbackBranch = buildBranchStepsFromAlternatives(
        meta?.alternatives ?? undefined,
        maxStepAttempts,
        maxSteps
      );
      if (fallbackBranch.length > 0) {
        steps = fallbackBranch;
      }
    }
    const agentAuditLog = getAgentAuditLogDelegate();
    if (agentAuditLog && runId) {
      await agentAuditLog.create({
        data: {
          runId,
          level: 'info',
          message: 'Loop guard completed.',
          metadata: {
            action,
            reason: parsed.reason ?? null,
            loop: loopSignal,
          },
        },
      });
    }
    return {
      action,
      ...(parsed.reason && { reason: parsed.reason }),
      questions: normalizeStringList(parsed.questions),
      evidence: normalizeStringList(parsed.evidence),
      steps,
      hierarchy,
      meta,
    };
  } catch (error) {
    logClientError(error);
    if (DEBUG_CHATBOT) {
      void ErrorSystem.logWarning('Loop guard failed', {
        service: 'agent-engine',
        action: 'loop-guard',
        runId,
        error: error instanceof Error ? error.message : String(error),
      });
    }
    return { action: 'continue', steps: [] };
  }
}

import { logAgentAudit } from '@/features/ai/agent-runtime/audit';
import { getBrowserContextSummary } from '@/features/ai/agent-runtime/browsing/context';
import { persistCheckpoint } from '@/features/ai/agent-runtime/memory/checkpoint';
import { buildPlanWithLLM, buildResumePlanReview } from '@/features/ai/agent-runtime/planning/llm';
import { buildBranchStepsFromAlternatives } from '@/features/ai/agent-runtime/planning/utils';
import type { PlanHierarchy } from '@/features/ai/agent-runtime/planning/utils';
import type {
  AgentDecision,
  AgentExecutionContext,
  PlanStep,
  PlannerMeta,
} from '@/shared/contracts/agent-runtime';

type CheckpointState = ReturnType<
  typeof import('@/features/ai/agent-runtime/memory/checkpoint').parseCheckpoint
>;

type PlanInitializationResult = {
  planSteps: PlanStep[];
  planHierarchy: PlanHierarchy | null;
  taskType: PlannerMeta['taskType'] | null;
  decision: AgentDecision;
  stepIndex: number;
  summaryCheckpoint: number;
  preferences: Record<string, unknown>;
};

type InitializePlanInput = {
  context: AgentExecutionContext;
  checkpoint: CheckpointState;
};

export async function initializePlanState(
  input: InitializePlanInput
): Promise<PlanInitializationResult> {
  const { context, checkpoint } = input;
  const {
    run,
    memoryContext,
    browserContext,
    settings,
    preferences,
    contextRegistry,
    plannerModel,
    loopGuardModel,
    memorySummarizationModel,
  } = context;

  let planSteps: PlanStep[];
  let planHierarchy: PlanHierarchy | null = null;
  let taskType: PlannerMeta['taskType'] | null;
  let decision: AgentDecision;
  let stepIndex = 0;
  let summaryCheckpoint = checkpoint?.summaryCheckpoint ?? 0;
  const nextPreferences: AgentExecutionContext['preferences'] = {
    ignoreRobotsTxt: Boolean(preferences.ignoreRobotsTxt),
    requireHumanApproval: Boolean(preferences.requireHumanApproval),
  };

  if (checkpoint?.steps?.length) {
    planSteps = checkpoint.steps;
    taskType = checkpoint.taskType ?? null;
    const checkpointPreferences = checkpoint.preferences ?? null;
    if (checkpointPreferences?.['ignoreRobotsTxt'] !== undefined) {
      nextPreferences.ignoreRobotsTxt = Boolean(checkpointPreferences['ignoreRobotsTxt']);
    }
    if (checkpointPreferences?.requireHumanApproval !== undefined) {
      nextPreferences.requireHumanApproval = Boolean(checkpointPreferences.requireHumanApproval);
    }
    if (typeof checkpoint.summaryCheckpoint === 'number') {
      summaryCheckpoint = checkpoint.summaryCheckpoint;
    }
    let resumedWithNewPlan = false;
    if (
      checkpoint.resumeRequestedAt &&
      checkpoint.resumeRequestedAt !== checkpoint.resumeProcessedAt
    ) {
      const rawResumeContext = await getBrowserContextSummary(run.id);
      const resumeContext: AgentExecutionContext['browserContext'] = rawResumeContext
        ? {
          url: rawResumeContext.url ?? '',
          title: rawResumeContext.title ?? null,
          domTextSample: rawResumeContext.domTextSample ?? '',
          logs: rawResumeContext.logs ?? [],
          uiInventory: rawResumeContext.uiInventory,
        }
        : null;
      const resumeReview = await buildResumePlanReview({
        prompt: run.prompt,
        memory: memoryContext,
        model: memorySummarizationModel,
        browserContext: resumeContext
          ? {
            url: resumeContext.url ?? '',
            title: resumeContext.title ?? null,
            domTextSample: resumeContext.domTextSample ?? '',
            logs: resumeContext.logs ?? [],
            uiInventory: resumeContext.uiInventory,
          }
          : null,
        currentPlan: planSteps,
        completedIndex: Math.max(stepIndex, 0),
        lastError: checkpoint.lastError ?? null,
        runId: run.id,
        maxSteps: settings.maxSteps,
        maxStepAttempts: settings.maxStepAttempts,
      });

      if (resumeReview.shouldReplan && resumeReview.steps.length > 0) {
        planSteps = resumeReview.steps;
        stepIndex = 0;
        resumedWithNewPlan = true;
        taskType = resumeReview.meta?.taskType ?? taskType;
        await logAgentAudit(run.id, 'warning', 'Resume plan refreshed.', {
          type: 'resume-plan',
          steps: planSteps,
          reason: resumeReview.reason,
          plannerMeta: resumeReview.meta ?? null,
          hierarchy: resumeReview.hierarchy ?? null,
        });
      } else {
        await logAgentAudit(run.id, 'info', 'Resume summary prepared.', {
          type: 'resume-summary',
          summary: resumeReview.summary ?? null,
          reason: resumeReview.reason,
          plannerMeta: resumeReview.meta ?? null,
        });
      }
      await persistCheckpoint({
        runId: run.id,
        steps: planSteps,
        activeStepId: planSteps[stepIndex]?.id ?? null,
        lastError: checkpoint.lastError ?? null,
        taskType,
        resumeRequestedAt: checkpoint.resumeRequestedAt,
        resumeProcessedAt: new Date().toISOString(),
        approvalRequestedStepId: checkpoint.approvalRequestedStepId ?? null,
        approvalGrantedStepId: checkpoint.approvalGrantedStepId ?? null,
        summaryCheckpoint,
        settings,
        preferences: nextPreferences,
        contextRegistry,
      });
    }
    if (!resumedWithNewPlan && checkpoint.activeStepId) {
      const activeIndex = planSteps.findIndex(
        (step: PlanStep) => step.id === checkpoint.activeStepId
      );
      stepIndex = activeIndex === -1 ? 0 : activeIndex;
    } else {
      const firstPending = planSteps.findIndex((step: PlanStep) => step.status !== 'completed');
      stepIndex = firstPending === -1 ? 0 : firstPending;
    }
    decision = {
      action: 'tool',
      reason: 'Resuming from checkpoint.',
      toolName: 'playwright',
    };
    await logAgentAudit(run.id, 'info', 'Checkpoint loaded.', {
      type: 'checkpoint-load',
      activeStepId: checkpoint.activeStepId ?? null,
      stepCount: planSteps.length,
    });
  } else {
    const planResult = await buildPlanWithLLM({
      prompt: run.prompt,
      memory: memoryContext,
      model: plannerModel,
      guardModel: loopGuardModel,
      browserContext: browserContext
        ? {
          url: browserContext.url ?? '',
          title: browserContext.title ?? null,
          domTextSample: browserContext.domTextSample ?? '',
          logs: browserContext.logs ?? [],
          uiInventory: browserContext.uiInventory,
        }
        : null,
      maxSteps: settings.maxSteps,
      maxStepAttempts: settings.maxStepAttempts,
    });

    planSteps = planResult.steps;
    planHierarchy = planResult.hierarchy ?? null;
    taskType = planResult.meta?.taskType ?? null;
    if (planSteps.length > 0) {
      await logAgentAudit(run.id, 'info', 'Plan created.', {
        type: 'plan',
        steps: planSteps,
        source: planResult.source,
        hierarchy: planHierarchy,
        plannerMeta: planResult.meta ?? null,
      });
      const branchAlternatives = buildBranchStepsFromAlternatives(
        planResult.meta?.alternatives ?? undefined,
        settings.maxStepAttempts,
        Math.min(6, settings.maxSteps)
      );
      if (branchAlternatives.length > 0) {
        await logAgentAudit(run.id, 'info', 'Plan branch created.', {
          type: 'plan-branch',
          branchSteps: branchAlternatives,
          reason: 'planner-alternatives',
          plannerMeta: planResult.meta ?? null,
        });
      }
    }
    decision = planResult.decision;
    await persistCheckpoint({
      runId: run.id,
      steps: planSteps,
      activeStepId: planSteps[0]?.id ?? null,
      lastError: null,
      taskType,
      summaryCheckpoint,
      approvalRequestedStepId: null,
      approvalGrantedStepId: null,
      settings,
      preferences: nextPreferences,
      contextRegistry,
    });
  }

  return {
    planSteps,
    planHierarchy,
    taskType,
    decision,
    stepIndex,
    summaryCheckpoint,
    preferences: nextPreferences,
  };
}

import { logAgentAudit } from '@/features/ai/agent-runtime/audit';
import { getBrowserContextSummary } from '@/features/ai/agent-runtime/browsing/context';
import { applyAgentRuntimeContextMemory } from '@/features/ai/agent-runtime/context-registry/shared';
import { addAgentMemory } from '@/features/ai/agent-runtime/memory';
import { addProblemSolutionMemory } from '@/features/ai/agent-runtime/memory/context';
import {
  buildAdaptivePlanReview,
  buildMidRunAdaptationWithLLM,
  buildSelfCheckReview,
  guardRepetitionWithLLM,
  summarizePlannerMemoryWithLLM,
} from '@/features/ai/agent-runtime/planning/llm';
import { shouldEvaluateReplan } from '@/features/ai/agent-runtime/planning/utils';
import { getAgentAuditLogDelegate } from '@/features/ai/agent-runtime/store-delegates';
import type {
  AgentExecutionContext,
  PlanStep,
  PlannerMeta,
} from '@/shared/contracts/agent-runtime';

import { persistCheckpoint } from '../memory/checkpoint';

type PostStepReviewInput = {
  context: AgentExecutionContext;
  step: PlanStep;
  stepIndex: number;
  previousUrl: string | null;
  lastContextUrl: string | null;
  planSteps: PlanStep[];
  taskType: PlannerMeta['taskType'] | null;
  memoryContext: string[];
  summaryCheckpoint: number;
  replanCount: number;
  selfCheckCount: number;
  stagnationCount: number;
  noContextCount: number;
  lastExtractionCheckAt: number;
  lastError: string | null;
  approvalRequestedStepId: string | null;
  approvalGrantedStepId: string | null;
  logBranchAlternatives: (meta: PlannerMeta | null | undefined, reason: string) => Promise<void>;
};

type PostStepReviewResult = {
  planSteps: PlanStep[];
  taskType: PlannerMeta['taskType'] | null;
  memoryContext: string[];
  summaryCheckpoint: number;
  replanCount: number;
  selfCheckCount: number;
  stagnationCount: number;
  noContextCount: number;
  lastExtractionCheckAt: number;
  lastError: string | null;
  requiresHuman: boolean;
  shouldBreak: boolean;
};

export async function runPostStepAdaptiveReviews(
  input: PostStepReviewInput
): Promise<PostStepReviewResult> {
  const {
    context,
    step,
    stepIndex,
    previousUrl,
    approvalRequestedStepId,
    approvalGrantedStepId,
    logBranchAlternatives,
  } = input;
  let {
    lastContextUrl,
    planSteps,
    taskType,
    memoryContext,
    summaryCheckpoint,
    replanCount,
    selfCheckCount,
    stagnationCount,
    noContextCount,
    lastExtractionCheckAt,
    lastError,
  } = input;
  const {
    run,
    settings,
    preferences,
    contextRegistry,
    contextRegistryPrompt,
    memoryKey,
    memoryValidationModel,
    memorySummarizationModel,
    plannerModel,
    selfCheckModel,
    loopGuardModel,
    resolvedModel,
  } = context;
  const summaryInterval = 5;
  const midRunInterval = 3;

  const completedCount = planSteps.filter((item: PlanStep) => item.status === 'completed').length;
  if (stagnationCount >= 2 && replanCount < settings.maxReplanCalls && completedCount > 0) {
    const stagnationContext = await getBrowserContextSummary(run.id);
    const stagnationReview = await buildAdaptivePlanReview({
      prompt: run.prompt,
      memory: memoryContext,
      model: plannerModel,
      browserContext: stagnationContext,
      currentPlan: planSteps,
      completedIndex: stepIndex,
      runId: run.id,
      maxSteps: settings.maxSteps,
      maxStepAttempts: settings.maxStepAttempts,
      trigger: 'stagnation',
      signals: {
        stagnationCount,
        lastContextUrl,
      },
    });
    if (stagnationReview.shouldReplan && stagnationReview.steps.length > 0) {
      const nextIndex = stepIndex + 1;
      const remainingSlots = Math.max(1, settings.maxSteps - nextIndex);
      const nextSteps = stagnationReview.steps.slice(0, remainingSlots);
      planSteps = [...planSteps.slice(0, nextIndex), ...nextSteps];
      taskType = stagnationReview.meta?.taskType ?? taskType;
      replanCount += 1;
      stagnationCount = 0;
      await logAgentAudit(run.id, 'warning', 'Plan re-evaluated.', {
        type: 'plan-replan',
        steps: planSteps,
        reason: 'stagnation',
        plannerMeta: stagnationReview.meta ?? null,
        hierarchy: stagnationReview.hierarchy ?? null,
        stepId: step.id,
        activeStepId: step.id,
      });
      await logBranchAlternatives(stagnationReview.meta, 'stagnation');
      await persistCheckpoint({
        runId: run.id,
        steps: planSteps,
        activeStepId: planSteps[nextIndex]?.id ?? null,
        lastError,
        taskType,
        approvalRequestedStepId,
        approvalGrantedStepId,
        summaryCheckpoint,
        settings,
        preferences,
        contextRegistry,
      });
    }
  }
  if (
    taskType === 'extract_info' &&
    completedCount >= 2 &&
    completedCount !== lastExtractionCheckAt &&
    replanCount < settings.maxReplanCalls
  ) {
    const agentAuditLog = getAgentAuditLogDelegate();
    const extractionAudit = agentAuditLog
      ? await agentAuditLog.findFirst<{ id: string }>({
      where: {
        runId: run.id,
        message: {
          in: ['Extracted product names.', 'Extracted emails.'],
        },
      },
      select: { id: true },
      })
      : null;
    lastExtractionCheckAt = completedCount;
    if (agentAuditLog && !extractionAudit) {
      const extractionContext = await getBrowserContextSummary(run.id);
      const extractionReview = await buildAdaptivePlanReview({
        prompt: run.prompt,
        memory: memoryContext,
        model: plannerModel,
        browserContext: extractionContext,
        currentPlan: planSteps,
        completedIndex: stepIndex,
        runId: run.id,
        maxSteps: settings.maxSteps,
        maxStepAttempts: settings.maxStepAttempts,
        trigger: 'missing-extraction',
        signals: {
          completedCount,
          lastContextUrl,
        },
      });
      if (extractionReview.shouldReplan && extractionReview.steps.length > 0) {
        const nextIndex = stepIndex + 1;
        const remainingSlots = Math.max(1, settings.maxSteps - nextIndex);
        const nextSteps = extractionReview.steps.slice(0, remainingSlots);
        planSteps = [...planSteps.slice(0, nextIndex), ...nextSteps];
        taskType = extractionReview.meta?.taskType ?? taskType;
        replanCount += 1;
        await logAgentAudit(run.id, 'warning', 'Plan re-evaluated.', {
          type: 'plan-replan',
          steps: planSteps,
          reason: 'missing-extraction',
          plannerMeta: extractionReview.meta ?? null,
          hierarchy: extractionReview.hierarchy ?? null,
          stepId: step.id,
          activeStepId: step.id,
        });
        await logBranchAlternatives(extractionReview.meta, 'missing-extraction');
        await persistCheckpoint({
          runId: run.id,
          steps: planSteps,
          activeStepId: planSteps[nextIndex]?.id ?? null,
          lastError,
          taskType,
          approvalRequestedStepId,
          approvalGrantedStepId,
          summaryCheckpoint,
          settings,
          preferences,
          contextRegistry,
        });
      }
    }
  }
  if (
    completedCount >= summaryInterval &&
    completedCount % summaryInterval === 0 &&
    completedCount !== summaryCheckpoint
  ) {
    const summaryContext = await getBrowserContextSummary(run.id);
    const summary = await summarizePlannerMemoryWithLLM({
      prompt: run.prompt,
      model: memorySummarizationModel,
      memory: memoryContext,
      steps: planSteps,
      browserContext: summaryContext,
      runId: run.id,
    });
    if (summary) {
      await addAgentMemory({
        runId: run.id,
        scope: 'session',
        content: summary,
        metadata: { type: 'planner-summary', completedCount },
      });
      memoryContext = applyAgentRuntimeContextMemory(
        [...memoryContext, summary],
        contextRegistryPrompt
      );
      summaryCheckpoint = completedCount;
      await logAgentAudit(run.id, 'info', 'Planner summary saved.', {
        type: 'planner-summary',
        completedCount,
        summary,
      });
      await persistCheckpoint({
        runId: run.id,
        steps: planSteps,
        activeStepId: planSteps[stepIndex + 1]?.id ?? null,
        lastError,
        taskType,
        approvalRequestedStepId,
        approvalGrantedStepId,
        summaryCheckpoint,
        settings,
        preferences,
        contextRegistry,
      });
    }
  }
  if (noContextCount >= 2 && replanCount < settings.maxReplanCalls && completedCount > 0) {
    const noContextReview = await buildAdaptivePlanReview({
      prompt: run.prompt,
      memory: memoryContext,
      model: plannerModel,
      browserContext: await getBrowserContextSummary(run.id),
      currentPlan: planSteps,
      completedIndex: stepIndex,
      runId: run.id,
      maxSteps: settings.maxSteps,
      maxStepAttempts: settings.maxStepAttempts,
      trigger: 'no-browser-context',
      signals: {
        noContextCount,
        lastContextUrl,
      },
    });
    if (noContextReview.shouldReplan && noContextReview.steps.length > 0) {
      const nextIndex = stepIndex + 1;
      const remainingSlots = Math.max(1, settings.maxSteps - nextIndex);
      const nextSteps = noContextReview.steps.slice(0, remainingSlots);
      planSteps = [...planSteps.slice(0, nextIndex), ...nextSteps];
      taskType = noContextReview.meta?.taskType ?? taskType;
      replanCount += 1;
      noContextCount = 0;
      await logAgentAudit(run.id, 'warning', 'Plan re-evaluated.', {
        type: 'plan-replan',
        steps: planSteps,
        reason: 'no-browser-context',
        plannerMeta: noContextReview.meta ?? null,
        hierarchy: noContextReview.hierarchy ?? null,
        stepId: step.id,
        activeStepId: step.id,
      });
      await logBranchAlternatives(noContextReview.meta, 'no-browser-context');
      await persistCheckpoint({
        runId: run.id,
        steps: planSteps,
        activeStepId: planSteps[nextIndex]?.id ?? null,
        lastError,
        taskType,
        approvalRequestedStepId,
        approvalGrantedStepId,
        summaryCheckpoint,
        settings,
        preferences,
        contextRegistry,
      });
    }
  }
  if (
    completedCount >= midRunInterval &&
    completedCount % midRunInterval === 0 &&
    replanCount < settings.maxReplanCalls
  ) {
    const adaptContext = await getBrowserContextSummary(run.id);
    const adaptResult = await buildMidRunAdaptationWithLLM({
      prompt: run.prompt,
      model: plannerModel,
      memory: memoryContext,
      steps: planSteps,
      browserContext: adaptContext,
      runId: run.id,
      maxSteps: settings.maxSteps,
      maxStepAttempts: settings.maxStepAttempts,
    });
    if (adaptResult.shouldAdapt && adaptResult.steps.length > 0) {
      const nextIndex = stepIndex + 1;
      const remainingSlots = Math.max(1, settings.maxSteps - nextIndex);
      const guardedSteps = await guardRepetitionWithLLM({
        prompt: run.prompt,
        model: loopGuardModel,
        memory: memoryContext,
        currentPlan: planSteps,
        candidateSteps: adaptResult.steps,
        runId: run.id,
        maxSteps: remainingSlots,
      });
      const nextSteps = guardedSteps.slice(0, remainingSlots);
      planSteps = [...planSteps.slice(0, nextIndex), ...nextSteps];
      taskType = adaptResult.meta?.taskType ?? taskType;
      replanCount += 1;
      await logAgentAudit(run.id, 'warning', 'Plan adapted mid-run.', {
        type: 'plan-adapt',
        steps: planSteps,
        reason: adaptResult.reason,
        plannerMeta: adaptResult.meta ?? null,
        hierarchy: adaptResult.hierarchy ?? null,
        stepId: step.id,
        activeStepId: step.id,
      });
      await logBranchAlternatives(adaptResult.meta, 'mid-run-adapt');
      await persistCheckpoint({
        runId: run.id,
        steps: planSteps,
        activeStepId: planSteps[nextIndex]?.id ?? null,
        lastError,
        taskType,
        approvalRequestedStepId,
        approvalGrantedStepId,
        summaryCheckpoint,
        settings,
        preferences,
        contextRegistry,
      });
    }
  }
  if (selfCheckCount < settings.maxSelfChecks) {
    const selfCheckContext = await getBrowserContextSummary(run.id);
    const selfCheck = await buildSelfCheckReview({
      prompt: run.prompt,
      memory: memoryContext,
      model: selfCheckModel,
      browserContext: selfCheckContext,
      step,
      stepIndex,
      lastError,
      taskType,
      completedCount,
      previousUrl,
      lastContextUrl,
      stagnationCount,
      noContextCount,
      replanCount,
      runId: run.id,
      maxSteps: settings.maxSteps,
      maxStepAttempts: settings.maxStepAttempts,
    });
    selfCheckCount += 1;
    await logAgentAudit(run.id, 'info', 'Self-check completed.', {
      type: 'self-check',
      stepId: step.id,
      stepTitle: step.title,
      action: selfCheck.action,
      reason: selfCheck.reason,
      notes: selfCheck.notes,
      questions: selfCheck.questions,
      evidence: selfCheck.evidence,
      confidence: selfCheck.confidence,
      missingInfo: selfCheck.missingInfo,
      blockers: selfCheck.blockers,
      hypotheses: selfCheck.hypotheses,
      verificationSteps: selfCheck.verificationSteps,
      toolSwitch: selfCheck.toolSwitch,
      abortSignals: selfCheck.abortSignals,
      finishSignals: selfCheck.finishSignals,
    });
    if (selfCheck.action === 'wait_human') {
      lastError = selfCheck.reason ?? 'Self-check requested human input.';
      return {
        planSteps,
        taskType,
        memoryContext,
        summaryCheckpoint,
        replanCount,
        selfCheckCount,
        stagnationCount,
        noContextCount,
        lastExtractionCheckAt,
        lastError,
        requiresHuman: true,
        shouldBreak: true,
      };
    }
    if (selfCheck.action === 'replan' && selfCheck.steps.length > 0) {
      const nextIndex = stepIndex + 1;
      const remainingSlots = Math.max(1, settings.maxSteps - nextIndex);
      const guardedSteps = await guardRepetitionWithLLM({
        prompt: run.prompt,
        model: loopGuardModel,
        memory: memoryContext,
        currentPlan: planSteps,
        candidateSteps: selfCheck.steps,
        runId: run.id,
        maxSteps: remainingSlots,
      });
      const nextSteps = guardedSteps.slice(0, remainingSlots);
      planSteps = [...planSteps.slice(0, nextIndex), ...nextSteps];
      taskType = selfCheck.meta?.taskType ?? taskType;
      await logAgentAudit(run.id, 'warning', 'Plan replaced by self-check.', {
        type: 'self-check-replan',
        steps: planSteps,
        reason: selfCheck.reason,
        plannerMeta: selfCheck.meta ?? null,
        hierarchy: selfCheck.hierarchy ?? null,
        stepId: step.id,
        activeStepId: step.id,
      });
      await logBranchAlternatives(selfCheck.meta, 'self-check');
      await persistCheckpoint({
        runId: run.id,
        steps: planSteps,
        activeStepId: planSteps[nextIndex]?.id ?? null,
        lastError,
        taskType,
        approvalRequestedStepId,
        approvalGrantedStepId,
        summaryCheckpoint,
        settings,
        preferences,
        contextRegistry,
      });
    }
  }
  if (
    previousUrl &&
    lastContextUrl &&
    lastContextUrl !== previousUrl &&
    replanCount < settings.maxReplanCalls
  ) {
    const shiftContext = await getBrowserContextSummary(run.id);
    const shiftReview = await buildAdaptivePlanReview({
      prompt: run.prompt,
      memory: memoryContext,
      model: plannerModel,
      browserContext: shiftContext,
      currentPlan: planSteps,
      completedIndex: stepIndex,
      runId: run.id,
      maxSteps: settings.maxSteps,
      maxStepAttempts: settings.maxStepAttempts,
      trigger: 'context-shift',
      signals: {
        previousUrl,
        lastContextUrl,
      },
    });
    if (shiftReview.shouldReplan && shiftReview.steps.length > 0) {
      const nextIndex = stepIndex + 1;
      const remainingSlots = Math.max(1, settings.maxSteps - nextIndex);
      const nextSteps = shiftReview.steps.slice(0, remainingSlots);
      planSteps = [...planSteps.slice(0, nextIndex), ...nextSteps];
      taskType = shiftReview.meta?.taskType ?? taskType;
      replanCount += 1;
      await logAgentAudit(run.id, 'warning', 'Plan re-evaluated.', {
        type: 'plan-replan',
        steps: planSteps,
        reason: 'context-shift',
        plannerMeta: shiftReview.meta ?? null,
        hierarchy: shiftReview.hierarchy ?? null,
        stepId: step.id,
        activeStepId: step.id,
      });
      await logBranchAlternatives(shiftReview.meta, 'context-shift');
      if (memoryKey) {
        await addProblemSolutionMemory({
          memoryKey,
          runId: run.id,
          problem: 'Context shifted (URL changed).',
          countermeasure: 'Replanned after context shift.',
          context: {
            stepId: step.id,
            stepTitle: step.title,
            reason: 'context-shift',
          },
          tags: ['context-shift'],
          model: memoryValidationModel ?? resolvedModel,
          summaryModel: memorySummarizationModel ?? resolvedModel,
          prompt: run.prompt,
        });
      }
      await persistCheckpoint({
        runId: run.id,
        steps: planSteps,
        activeStepId: planSteps[nextIndex]?.id ?? null,
        lastError,
        taskType,
        approvalRequestedStepId,
        approvalGrantedStepId,
        summaryCheckpoint,
        settings,
        preferences,
        contextRegistry,
      });
    }
  }
  if (
    shouldEvaluateReplan(stepIndex, planSteps, settings.replanEverySteps) &&
    replanCount < settings.maxReplanCalls
  ) {
    const reviewContext = await getBrowserContextSummary(run.id);
    const reviewResult = await buildAdaptivePlanReview({
      prompt: run.prompt,
      memory: memoryContext,
      model: plannerModel,
      browserContext: reviewContext,
      currentPlan: planSteps,
      completedIndex: stepIndex,
      runId: run.id,
      maxSteps: settings.maxSteps,
      maxStepAttempts: settings.maxStepAttempts,
      trigger: 'scheduled-replan',
      signals: {
        completedCount,
        replanEverySteps: settings.replanEverySteps,
      },
    });
    if (reviewResult.shouldReplan && reviewResult.steps.length > 0) {
      const nextIndex = stepIndex + 1;
      const remainingSlots = Math.max(1, settings.maxSteps - nextIndex);
      const guardedSteps = await guardRepetitionWithLLM({
        prompt: run.prompt,
        model: loopGuardModel,
        memory: memoryContext,
        currentPlan: planSteps,
        candidateSteps: reviewResult.steps,
        runId: run.id,
        maxSteps: remainingSlots,
      });
      const nextSteps = guardedSteps.slice(0, remainingSlots);
      planSteps = [...planSteps.slice(0, nextIndex), ...nextSteps];
      taskType = reviewResult.meta?.taskType ?? taskType;
      replanCount += 1;
      await logAgentAudit(run.id, 'warning', 'Plan re-evaluated.', {
        type: 'plan-replan',
        steps: planSteps,
        reason: reviewResult.reason,
        plannerMeta: reviewResult.meta ?? null,
        hierarchy: reviewResult.hierarchy ?? null,
        stepId: step.id,
        activeStepId: step.id,
      });
      await logBranchAlternatives(reviewResult.meta, 'scheduled-replan');
      await persistCheckpoint({
        runId: run.id,
        steps: planSteps,
        activeStepId: planSteps[nextIndex]?.id ?? null,
        lastError,
        taskType,
        approvalRequestedStepId,
        approvalGrantedStepId,
        summaryCheckpoint,
        settings,
        preferences,
        contextRegistry,
      });
    }
  }

  return {
    planSteps,
    taskType,
    memoryContext,
    summaryCheckpoint,
    replanCount,
    selfCheckCount,
    stagnationCount,
    noContextCount,
    lastExtractionCheckAt,
    lastError,
    requiresHuman: false,
    shouldBreak: false,
  };
}

import { logAgentAudit } from '@/features/ai/agent-runtime/audit';
import {
  evaluateApprovalGateWithLLM,
  requiresHumanApproval as requiresHumanApprovalHeuristic,
} from '@/features/ai/agent-runtime/audit/gate';
import { getBrowserContextSummary } from '@/features/ai/agent-runtime/browsing/context';
import { buildCheckpointState } from '@/features/ai/agent-runtime/memory/checkpoint';
import { getChatbotAgentRunDelegate } from '@/features/ai/agent-runtime/store-delegates';
import { type AgentExecutionContext, type PlanStep, type PlannerMeta } from '@/shared/contracts/agent-runtime';
import type { InputJsonValue } from '@/shared/contracts/json';

export async function evaluateApproval(args: {
  step: PlanStep;
  context: AgentExecutionContext;
  runId: string;
  approvalGrantedStepId: string | null;
  planSteps: PlanStep[];
  lastError: string | null;
  taskType: PlannerMeta['taskType'] | null;
  approvalRequestedStepId: string | null;
  summaryCheckpoint: number;
}): Promise<{
  requiresApproval: boolean;
  requiresHuman: boolean;
  approvalSource: string;
  approvalReason: string | null;
  approvalRisk: string | null;
  updatedApprovalRequestedStepId: string | null;
}> {
  const {
    step,
    context,
    runId,
    approvalGrantedStepId,
    planSteps,
    lastError,
    taskType,
    approvalRequestedStepId,
    summaryCheckpoint,
  } = args;

  const { preferences, approvalGateModel, run, settings, contextRegistry } = context;

  let requiresApproval = false;
  let approvalReason: string | null = null;
  let approvalRisk: string | null = null;
  let approvalSource = 'heuristic';

  if (preferences.requireHumanApproval && approvalGrantedStepId !== step.id) {
    requiresApproval = requiresHumanApprovalHeuristic(step, run.prompt);
    if (!requiresApproval && approvalGateModel) {
      const gateContext = await getBrowserContextSummary(runId);
      const gateDecision = await evaluateApprovalGateWithLLM({
        prompt: run.prompt,
        step,
        model: approvalGateModel,
        browserContext: gateContext,
        runId,
      });
      if (gateDecision) {
        requiresApproval = gateDecision.requiresApproval;
        approvalReason = gateDecision.reason ?? null;
        approvalRisk = gateDecision.riskLevel ?? null;
        approvalSource = 'policy-model';
        await logAgentAudit(runId, 'info', 'Approval gate evaluated.', {
          type: 'approval-gate-review',
          stepId: step.id,
          stepTitle: step.title,
          requiresApproval,
          reason: approvalReason,
          riskLevel: approvalRisk,
          model: approvalGateModel,
        });
      }
    }
  }

  let nextApprovalRequestedStepId = approvalRequestedStepId;

  if (preferences.requireHumanApproval && requiresApproval && approvalGrantedStepId !== step.id) {
    nextApprovalRequestedStepId = step.id;
    const chatbotAgentRun = getChatbotAgentRunDelegate();
    if (chatbotAgentRun) {
      await chatbotAgentRun.update({
        where: { id: runId },
        data: {
          status: 'waiting_human',
          requiresHumanIntervention: true,
          activeStepId: step.id,
          planState: buildCheckpointState({
            steps: planSteps,
            activeStepId: step.id,
          lastError,
          taskType,
          approvalRequestedStepId: nextApprovalRequestedStepId,
            approvalGrantedStepId,
            summaryCheckpoint,
          settings,
          preferences,
          contextRegistry,
          }) as InputJsonValue,
          checkpointedAt: new Date(),
          logLines: {
            push: `[${new Date().toISOString()}] Approval required for step.`,
          },
        },
      });
    }
    await logAgentAudit(runId, 'warning', 'Approval required.', {
      type: 'approval-gate',
      stepId: step.id,
      stepTitle: step.title,
      source: approvalSource,
      reason: approvalReason,
      riskLevel: approvalRisk,
    });
    return {
      requiresApproval: true,
      requiresHuman: true,
      approvalSource,
      approvalReason,
      approvalRisk,
      updatedApprovalRequestedStepId: nextApprovalRequestedStepId,
    };
  }

  return {
    requiresApproval: false,
    requiresHuman: false,
    approvalSource,
    approvalReason,
    approvalRisk,
    updatedApprovalRequestedStepId: nextApprovalRequestedStepId,
  };
}

import {
  type AgentLongTermMemoryRecord,
  getAgentLongTermMemoryDelegate,
} from '@/features/ai/agent-runtime/store-delegates';
import type { InputJsonValue } from '@/shared/contracts/json';
import { resolveBrainExecutionConfigForCapability } from '@/shared/lib/ai-brain/server';
import {
  runBrainChatCompletion,
  supportsBrainJsonMode,
} from '@/shared/lib/ai-brain/server-runtime-client';
import { ErrorSystem } from '@/shared/utils/observability/error-system';
import { DEBUG_CHATBOT, parseJsonObject } from './shared';
async function handleMemoryError(
  error: unknown,
  params: { memoryKey: string; runId?: string | null }
): Promise<void> {
  void ErrorSystem.captureException(error);
  try {
    await ErrorSystem.captureException(error, {
      service: 'agent-memory',
      action: 'addAgentLongTermMemory',
      memoryKey: params.memoryKey,
      runId: params.runId ?? undefined,
    });
  } catch (logError) {
    void ErrorSystem.captureException(logError);
    if (DEBUG_CHATBOT) {
      const { logger } = await import('@/shared/utils/logger');
      logger.error(
        '[chatbot][agent][memory] Failed to add long-term memory (and logging failed)',
        logError,
        {
          memoryKey: params.memoryKey,
          runId: params.runId,
          error,
        }
      );
    }
  }
}

export async function addAgentLongTermMemory(params: {
  memoryKey: string;
  runId?: string | null;
  personaId?: string | null;
  content: string;
  summary?: string | null;
  tags?: string[];
  topicHints?: string[];
  moodHints?: string[];
  sourceType?: string | null;
  sourceId?: string | null;
  sourceLabel?: string | null;
  sourceCreatedAt?: Date | string | null;
  metadata?: Record<string, unknown>;
  importance?: number | null;
}): Promise<AgentLongTermMemoryRecord | null> {
  const agentLongTermMemory = getAgentLongTermMemoryDelegate();
  if (agentLongTermMemory === null) {
    void ErrorSystem.logWarning(
      '[chatbot][agent][memory] Long-term memory table not initialized.',
      {
        service: 'agent-memory',
      }
    );
    return null;
  }
  try {
    return await agentLongTermMemory.create<AgentLongTermMemoryRecord>({
      data: {
        memoryKey: params.memoryKey,
        runId: params.runId ?? null,
        personaId: params.personaId ?? null,
        content: params.content,
        summary: params.summary ?? null,
        tags: params.tags ?? [],
        topicHints: params.topicHints ?? [],
        moodHints: params.moodHints ?? [],
        sourceType: params.sourceType ?? null,
        sourceId: params.sourceId ?? null,
        sourceLabel: params.sourceLabel ?? null,
        sourceCreatedAt:
          params.sourceCreatedAt instanceof Date
            ? params.sourceCreatedAt
            : (params.sourceCreatedAt !== null ? new Date(params.sourceCreatedAt) : null),
        ...(params.metadata !== null && {
          metadata: params.metadata as InputJsonValue,
        }),
        importance: params.importance ?? null,
        lastAccessedAt: new Date(),
      },
    });
  } catch (error) {
    await handleMemoryError(error, { memoryKey: params.memoryKey, runId: params.runId });
    throw error;
  }
}

async function prepareMemoryValidation(params: {
  model?: string | null;
  prompt?: string | null;
}) {
  const config = await resolveBrainExecutionConfigForCapability('agent_runtime.memory_validation', {
    defaultTemperature: 0.2,
    defaultMaxTokens: 500,
    runtimeKind: 'validation',
  });
  const model = (params.model !== null && params.model.trim() !== '') ? params.model.trim() : config.modelId;
  const prompt = params.prompt ?? '';
  if (model === null) {
    throw new Error('AI Brain memory validation model is not configured.');
  }
  return { config, model, prompt };
}

export async function validateAgentLongTermMemory(params: {
  model?: string | null;
  prompt?: string | null;
  content: string;
  summary?: string | null;
  metadata?: Record<string, unknown>;
}): Promise<{ valid: boolean; issues: string[]; reason: string | null; model: string | null }> {
  const { config, model, prompt } = await prepareMemoryValidation(params);

  try {
    const response = await runBrainChatCompletion({
      modelId: model,
      temperature: config.temperature,
      maxTokens: config.maxTokens,
      jsonMode: supportsBrainJsonMode(model),
      messages: [
        {
          role: 'system',
          content:
            'You validate long-term memory entries. Return only JSON with keys: valid (boolean), issues (array of strings), reason. Mark invalid if the prompt implies a target URL/domain that conflicts with metadata.url or metadata.run.url. Prefer strictness if evidence is missing.',
        },
        {
          role: 'user',
          content: JSON.stringify({
            prompt,
            content: params.content,
            summary: params.summary ?? null,
            metadata: params.metadata ?? null,
          }),
        },
      ],
    });
    const parsed = parseJsonObject(response.text) as {
      valid?: unknown;
      issues?: unknown;
      reason?: unknown;
    } | null;
    const issues = Array.isArray(parsed?.issues)
      ? (parsed.issues.filter((item: unknown): item is string => typeof item === 'string'))
      : [];
    return {
      valid: typeof parsed?.valid === 'boolean' ? parsed.valid : true,
      issues,
      reason: typeof parsed?.reason === 'string' ? parsed.reason : null,
      model,
    };
  } catch (error) {
    void ErrorSystem.captureException(error);
    return {
      valid: false,
      issues: [
        `Memory validation failed: ${error instanceof Error ? error.message : String(error)}`,
      ],
      reason: null,
      model,
    };
  }
}

async function summarizeMemory(params: {
  summaryModel?: string | null;
  prompt?: string | null;
  content: string;
  summary?: string | null;
  metadata?: Record<string, unknown>;
}): Promise<string | null> {
  const config = await resolveBrainExecutionConfigForCapability(
    'agent_runtime.memory_summarization',
    {
      defaultTemperature: 0.2,
      defaultMaxTokens: 300,
      runtimeKind: 'chat',
    }
  );
  const summaryModel = (params.summaryModel !== null && params.summaryModel.trim() !== '') ? params.summaryModel.trim() : config.modelId;
  if (summaryModel === null) return params.summary ?? null;

  try {
    const response = await runBrainChatCompletion({
      modelId: summaryModel,
      temperature: config.temperature,
      maxTokens: config.maxTokens,
      jsonMode: supportsBrainJsonMode(summaryModel),
      messages: [
        {
          role: 'system',
          content:
            'You write concise long-term memory summaries. Return only JSON with key summary (string). Keep it 1-2 sentences.',
        },
        {
          role: 'user',
          content: JSON.stringify({
            prompt: params.prompt ?? null,
            content: params.content,
            metadata: params.metadata ?? null,
          }),
        },
      ],
    });
    const parsed = parseJsonObject(response.text) as { summary?: unknown } | null;
    if (typeof parsed?.summary === 'string' && parsed.summary.trim() !== '') {
      return parsed.summary.trim();
    }
  } catch (error) {
    void ErrorSystem.captureException(error);
  }
  return params.summary ?? null;
}

export async function validateAndAddAgentLongTermMemory(params: {
  memoryKey: string;
  runId?: string | null;
  personaId?: string | null;
  content: string;
  summary?: string | null;
  summaryModel?: string | null;
  tags?: string[];
  topicHints?: string[];
  moodHints?: string[];
  sourceType?: string | null;
  sourceId?: string | null;
  sourceLabel?: string | null;
  sourceCreatedAt?: Date | string | null;
  metadata?: Record<string, unknown>;
  importance?: number | null;
  model?: string | null;
  prompt?: string | null;
}): Promise<{
  skipped: boolean;
  validation: Awaited<ReturnType<typeof validateAgentLongTermMemory>>;
  record?: AgentLongTermMemoryRecord | null;
}> {
  const summary = await summarizeMemory(params);

  const validation = await validateAgentLongTermMemory({
    ...(params.model !== null && { model: params.model }),
    ...(params.prompt !== null && { prompt: params.prompt }),
    content: params.content,
    ...(summary !== null && { summary }),
    ...(params.metadata !== null && { metadata: params.metadata }),
  });

  if (!validation.valid) {
    return { skipped: true, validation };
  }

  const record = await addAgentLongTermMemory({
    memoryKey: params.memoryKey,
    runId: params.runId ?? null,
    personaId: params.personaId ?? null,
    content: params.content,
    ...(summary !== null && { summary }),
    tags: params.tags ?? [],
    topicHints: params.topicHints ?? [],
    moodHints: params.moodHints ?? [],
    sourceType: params.sourceType ?? null,
    sourceId: params.sourceId ?? null,
    sourceLabel: params.sourceLabel ?? null,
    sourceCreatedAt: params.sourceCreatedAt ?? null,
    metadata: params.metadata ?? undefined,
    importance: params.importance ?? null,
  });

  return { skipped: false, validation, record };
}

function getListFilters(params: {
  memoryKey?: string;
  personaId?: string | null;
  tags?: string[];
}): Record<string, unknown> {
  const where: Record<string, unknown> = {};
  if (params.memoryKey != null && params.memoryKey !== '') {
    where.memoryKey = params.memoryKey;
  }
  if (params.personaId != null && params.personaId !== '') {
    where.personaId = params.personaId;
  }
  if (Array.isArray(params.tags) && params.tags.length > 0) {
    where.tags = { hasSome: params.tags };
  }
  return where;
}

export async function listAgentLongTermMemory(params: {
  memoryKey?: string;
  personaId?: string | null;
  limit?: number;
  tags?: string[];
}): Promise<AgentLongTermMemoryRecord[]> {
  const agentLongTermMemory = getAgentLongTermMemoryDelegate();
  if (agentLongTermMemory == null) {
    void ErrorSystem.logWarning(
      '[chatbot][agent][memory] Long-term memory table not initialized.',
      { service: 'agent-memory' }
    );
    return [];
  }
  if ((params.memoryKey == null || params.memoryKey === '') && (params.personaId == null || params.personaId === '')) {
    return [];
  }

  const where = getListFilters(params);
  const items = await agentLongTermMemory.findMany<AgentLongTermMemoryRecord>({
    where,
    orderBy: { updatedAt: 'desc' },
    take: params.limit ?? 5,
  });

  const ids = items.map((item: AgentLongTermMemoryRecord) => item.id);
  if (ids.length > 0) {
    await agentLongTermMemory.updateMany({
      where: { id: { in: ids } },
      data: { lastAccessedAt: new Date() },
    });
  }
  return items;
}

