export async function summarizePlannerMemoryWithLLM({
  prompt,
  model,
  memory,
  steps,
  browserContext,
  runId,
}: {
  prompt: string;
  model: string;
  memory: string[];
  steps: PlanStep[];
  browserContext?: {
    url: string;
    title: string | null;
    domTextSample: string;
    logs: { level: string; message: string }[];
    uiInventory?: unknown;
  } | null;
  runId?: string;
}): Promise<string | null> {
  try {
    const content = await runPlanningEvaluationTask({
      model,
      systemPrompt:
        'You summarize progress for long-running plans. Return only JSON with keys: summary, keyDecisions[], risks[]. Keep summary under 80 words.',
      userContent: JSON.stringify({
        prompt,
        memory,
        steps: steps.map((step: PlanStep) => ({
          title: step.title,
          status: step.status,
          phase: step.phase,
        })),
        browserContext,
      }),
    });
    const parsed = parsePlanJson(content) as {
      summary?: string;
      keyDecisions?: string[];
      risks?: string[];
    } | null;
    if (!parsed?.summary) return null;
    const { summary } = parsed;
    const decisions = Array.isArray(parsed.keyDecisions)
      ? parsed.keyDecisions.filter((item: unknown) => typeof item === 'string')
      : [];
    const risks = Array.isArray(parsed.risks)
      ? parsed.risks.filter((item: unknown) => typeof item === 'string')
      : [];
    const packed = [
      summary,
      decisions.length ? `Decisions: ${decisions.join(' | ')}` : null,
      risks.length ? `Risks: ${risks.join(' | ')}` : null,
    ]
      .filter(Boolean)
      .join('\n');
    const agentAuditLog = getAgentAuditLogDelegate();
    if (agentAuditLog && runId) {
      await agentAuditLog.create({
        data: {
          runId,
          level: 'info',
          message: 'Planner memory summary created.',
          metadata: {
            summary,
            keyDecisions: decisions,
            risks,
          },
        },
      });
    }
    return packed;
  } catch (error) {
    void ErrorSystem.captureException(error);
    void ErrorSystem.logWarning('[chatbot][agent][engine] Planner summary failed', {
      ...(runId && { runId }),
      error,
    });
    return null;
  }
}

export async function buildMidRunAdaptationWithLLM({
  prompt,
  model,
  memory,
  steps,
  browserContext,
  runId,
  maxSteps,
  maxStepAttempts,
}: {
  prompt: string;
  model: string;
  memory: string[];
  steps: PlanStep[];
  browserContext?: {
    url: string;
    title: string | null;
    domTextSample: string;
    logs: { level: string; message: string }[];
    uiInventory?: unknown;
  } | null;
  runId?: string;
  maxSteps: number;
  maxStepAttempts: number;
}): Promise<{
  shouldAdapt: boolean;
  reason?: string;
  steps: PlanStep[];
  hierarchy?: ReturnType<typeof normalizePlanHierarchy> | null;
  meta?: PlannerMeta | null;
}> {
  try {
    const content = await runPlanningEvaluationTask({
      model,
      systemPrompt:
        'You are a mid-run adaptation planner. Return only JSON with keys: shouldAdapt, reason, goals, critique, alternatives, taskType, summary, constraints, successSignals. shouldAdapt is boolean. If shouldAdapt is true, include goals (planner schema with priority/dependsOn) or steps: array of {title, tool, expectedObservation, successCriteria, phase, priority, dependsOn}. critique: {assumptions[], risks[], unknowns[], safetyChecks[], questions[]}. alternatives: array of {title, rationale, steps:[{title, tool, expectedObservation, successCriteria, phase, priority, dependsOn}]}. summary is short. constraints and successSignals are arrays.',
      userContent: JSON.stringify({
        prompt,
        memory,
        steps: steps.map((step: PlanStep) => ({
          title: step.title,
          status: step.status,
          tool: step.tool,
          expectedObservation: step.expectedObservation,
          successCriteria: step.successCriteria,
        })),
        browserContext,
        maxSteps,
      }),
    });
    const parsed = parsePlanJson(content) as {
      shouldAdapt?: boolean;
      reason?: string;
      steps?: Array<{
        title?: string;
        tool?: string;
        expectedObservation?: string;
        successCriteria?: string;
        phase?: string;
        priority?: number;
        dependsOn?: number[] | string[];
      }>;
      goals?: Array<{
        title?: string;
        successCriteria?: string;
        subgoals?: Array<{
          title?: string;
          successCriteria?: string;
          steps?: Array<{
            title?: string;
            tool?: string;
            expectedObservation?: string;
            successCriteria?: string;
            phase?: string;
            priority?: number;
            dependsOn?: number[] | string[];
          }>;
        }>;
      }>;
      critique?: PlannerCritique;
      alternatives?: PlannerAlternative[];
      summary?: string;
      constraints?: string[];
      successSignals?: string[];
      taskType?: string;
    } | null;
    if (!parsed) return { shouldAdapt: false, steps: [] };
    if (!parsed.shouldAdapt) return { shouldAdapt: false, steps: [] };
    const meta = normalizePlannerMeta(parsed);
    const hierarchy = normalizePlanHierarchy(parsed);
    const hierarchySteps = hierarchy ? flattenPlanHierarchy(hierarchy) : [];
    const stepSpecs = hierarchySteps.length > 0 ? hierarchySteps : (parsed.steps ?? []);
    let stepsResult = buildPlanStepsFromSpecs(
      normalizePlanStepSpecs(stepSpecs),
      meta,
      true,
      maxStepAttempts
    ).slice(0, maxSteps);
    if (stepsResult.length === 0) {
      const fallbackBranch = buildBranchStepsFromAlternatives(
        meta?.alternatives ?? undefined,
        maxStepAttempts,
        maxSteps
      );
      if (fallbackBranch.length > 0) {
        stepsResult = fallbackBranch;
      }
    }
    const result: {
      shouldAdapt: boolean;
      reason?: string;
      steps: PlanStep[];
      hierarchy?: ReturnType<typeof normalizePlanHierarchy> | null;
      meta?: PlannerMeta | null;
    } = {
      shouldAdapt: true,
      steps: stepsResult,
      hierarchy,
      meta,
    };
    if (typeof parsed.reason === 'string') {
      result.reason = parsed.reason;
    }
    return result;
  } catch (error) {
    void ErrorSystem.captureException(error);
    void ErrorSystem.logWarning('[chatbot][agent][engine] Mid-run adaptation failed', {
      ...(runId && { runId }),
      error,
    });
    return { shouldAdapt: false, steps: [] };
  }
}

import { 
  parsePlanJson, 
  normalizePlanStepSpecs, 
  buildPlanStepsFromSpecs 
} from '@/features/ai/agent-runtime/planning/utils';
import { runPlanningEvaluationTask } from '../core';
import { getAgentAuditLogDelegate } from '@/features/ai/agent-runtime/store-delegates';
import { ErrorSystem } from '@/shared/utils/observability/error-system';
import type { PlanStep, PlannerMeta } from '@/shared/contracts/agent-runtime';

export interface EvaluationResult {
  score: number;
  revisedSteps: PlanStep[];
}

const runEvaluationTask = async (params: {
  model: string;
  prompt: string;
  memory: string[];
  steps: PlanStep[];
  maxSteps: number;
}): Promise<string> => {
  return await runPlanningEvaluationTask({
    model: params.model,
    systemPrompt: 'You evaluate plans. Return only JSON with keys: score (0-100), revisedSteps.',
    userContent: JSON.stringify({
      prompt: params.prompt,
      memory: params.memory,
      steps: params.steps.map((s) => ({ title: s.title, tool: s.tool })),
      maxSteps: params.maxSteps,
    }),
  });
};

export async function evaluatePlanWithLLM(params: {
  prompt: string;
  model: string;
  memory: string[];
  steps: PlanStep[];
  meta: PlannerMeta | null;
  runId?: string;
  maxSteps: number;
  maxStepAttempts: number;
}): Promise<EvaluationResult | null> {
  const { prompt, model, memory, steps, meta, runId, maxSteps, maxStepAttempts } = params;
  if (steps.length < 2) return null;

  try {
    const content = await runEvaluationTask({ prompt, model, memory, steps, maxSteps });
    const parsed = parsePlanJson(content) as { score?: unknown; revisedSteps?: unknown[] } | null;
    if (!parsed) return null;

    const score = (typeof parsed.score === 'number' && parsed.score >= 0) ? parsed.score : 100;
    const revisedSpecs = Array.isArray(parsed.revisedSteps) ? parsed.revisedSteps : [];

    const revisedSteps = revisedSpecs.length > 0
      ? buildPlanStepsFromSpecs(
          normalizePlanStepSpecs(revisedSpecs as any[]),
          meta ?? {},
          true,
          maxStepAttempts
        ).slice(0, maxSteps)
      : [];

    const agentAuditLog = getAgentAuditLogDelegate();
    if (agentAuditLog !== null && runId !== undefined) {
      await agentAuditLog.create({
        data: {
          runId,
          level: 'info',
          message: 'Plan evaluated.',
          metadata: { score, revisedSteps: revisedSteps.length },
        },
      });
    }

    return { score, revisedSteps };
  } catch (error) {
    await ErrorSystem.captureException(error);
    return null;
  }
}

