import type { Page, Locator } from 'playwright';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


export type LoginCandidate = {
  tag: string;
  id: string | null;
  name: string | null;
  type: string | null;
  text: string | null;
  placeholder: string | null;
  ariaLabel: string | null;
  selector: string | null;
  score: number;
};

export type LoginCandidates = {
  inputs: LoginCandidate[];
  buttons: LoginCandidate[];
};

export const findFirstVisible = async (locator: Locator): Promise<Locator | null> => {
  const count = await locator.count();
  for (let i = 0; i < count; i += 1) {
    const candidate = locator.nth(i);
    if (await candidate.isVisible()) {
      return candidate;
    }
  }
  return null;
};

export const dismissConsent = async (
  page: Page,
  label: string,
  log?: (level: string, message: string, metadata?: Record<string, unknown>) => Promise<void>,
  activeStepId?: string | null
): Promise<void> => {
  if (!page) return;
  const buttonText = /accept|agree|ok|got it|allow all|accept all|dismiss|close/i;
  const selectors = [
    'button',
    '[role=\'button\']',
    'input[type=\'button\']',
    'input[type=\'submit\']',
    '[data-testid*=\'consent\' i]',
    '[data-testid*=\'cookie\' i]',
    '[aria-label*=\'accept\' i]',
    '[aria-label*=\'cookie\' i]',
  ];
  try {
    const candidates = page.locator(selectors.join(', '));
    const count = await candidates.count();
    for (let i = 0; i < count; i += 1) {
      const candidate = candidates.nth(i);
      const text = (await candidate.innerText()).trim();
      if (text && buttonText.test(text)) {
        await candidate.click({ timeout: 2000 });
        if (log) {
          await log('info', 'Dismissed consent banner.', {
            label,
            text,
            stepId: activeStepId ?? null,
          });
        }
        return;
      }
    }
  } catch (error) {
    logClientError(error);

    // ignore consent failures
  }
};

export const inferLoginCandidates = async (
  page: Page,
  log?: (level: string, message: string, metadata?: Record<string, unknown>) => Promise<void>,
  activeStepId?: string | null
): Promise<LoginCandidates | null> => {
  if (!page) return null;
  try {
    const candidates = await page.evaluate<LoginCandidates>(() => {
      const documentRef = document;

      const cssPath = (el: Element): string | null => {
        if (!(el instanceof Element)) return null;
        if (el.id) {
          return `#${CSS.escape(el.id)}`;
        }
        const parts: string[] = [];
        let node: Element | null = el;
        while (node !== null) {
          if (node.nodeType !== 1 || node === documentRef.documentElement) break;
          const currentNode: Element = node;
          let part = currentNode.tagName.toLowerCase();
          const name = currentNode.getAttribute('name');
          const dataTest =
            currentNode.getAttribute('data-testid') ||
            currentNode.getAttribute('data-test') ||
            currentNode.getAttribute('data-qa');
          if (name) {
            part += `[name="${name.replace(/"/g, '"')}"]`;
          } else if (dataTest) {
            part += `[data-testid="${dataTest.replace(/"/g, '"')}"]`;
          }
          const parent = currentNode.parentElement;
          if (parent) {
            const siblings = Array.from(parent.children as HTMLCollectionOf<Element>, (child) => child);
            const matchingSiblings = siblings.filter((child) => child.tagName === currentNode.tagName);
            if (matchingSiblings.length > 1) {
              const index = matchingSiblings.indexOf(currentNode) + 1;
              part += `:nth-of-type(${index})`;
            }
          }
          parts.unshift(part);
          node = currentNode.parentElement;
        }
        return parts.join(' > ');
      };

      const scoreInput = (el: HTMLInputElement): number => {
        const attrs = [
          el.name,
          el.id,
          el.placeholder,
          el.getAttribute('aria-label'),
          el.getAttribute('autocomplete'),
        ]
          .filter(Boolean)
          .join(' ')
          .toLowerCase();
        let score = 0;
        if (el.type === 'email') score += 5;
        if (el.type === 'password') score += 5;
        if (attrs.includes('email')) score += 4;
        if (attrs.includes('user') || attrs.includes('login')) score += 3;
        if (attrs.includes('password') || attrs.includes('pass')) score += 4;
        return score;
      };

      const describe = (
        el: Element
      ): {
        tag: string;
        id: string | null;
        name: string | null;
        type: string | null;
        text: string | null;
        placeholder: string | null;
        ariaLabel: string | null;
        selector: string | null;
      } => ({
        tag: el.tagName.toLowerCase(),
        id: (el as HTMLElement).id || null,
        name: (el as HTMLInputElement).name || null,
        type: (el as HTMLInputElement).type || null,
        text: (el as HTMLElement).innerText?.trim().slice(0, 120) || null,
        placeholder: (el as HTMLInputElement).placeholder || null,
        ariaLabel: el.getAttribute('aria-label'),
        selector: cssPath(el),
      });

      const inputs = Array.from(
        documentRef.querySelectorAll('input, textarea, select')
      )
        .filter((el: Element) => (el as HTMLElement).offsetParent !== null)
        .map((el: Element) => ({
          ...describe(el),
          score: el instanceof HTMLInputElement ? scoreInput(el) : 0,
        }))
        .sort((a: { score: number }, b: { score: number }) => b.score - a.score)
        .slice(0, 12);

      const buttons = Array.from(
        documentRef.querySelectorAll('button, input[type=\'submit\'], input[type=\'button\']')
      )
        .filter((el: Element) => (el as HTMLElement).offsetParent !== null)
        .map((el: Element) => ({
          ...describe(el),
          score: /log in|login|sign in|submit|continue|zaloguj|zaloguj się/i.test(
            (el as HTMLElement).innerText || (el as HTMLInputElement).value || ''
          )
            ? 5
            : 1,
        }))
        .sort((a: { score: number }, b: { score: number }) => b.score - a.score)
        .slice(0, 12);

      return { inputs, buttons };
    });
    if (log) {
      await log('info', 'Inferred login candidates.', {
        stepId: activeStepId ?? null,
        candidates,
      });
    }
    return candidates;
  } catch (error) {
    logClientError(error);
    if (log) {
      await log('warning', 'Failed to infer login candidates.', {
        error: error instanceof Error ? error.message : String(error),
        stepId: activeStepId ?? null,
      });
    }
  }
  return null;
};

export const ensureLoginFormVisible = async (
  page: Page,
  _runId: string,
  log?: (level: string, message: string, metadata?: Record<string, unknown>) => Promise<void>
): Promise<boolean | undefined> => {
  if (!page) return;
  const passwordSelector =
    'input[type="password"], input[name*="pass" i], input[autocomplete*="current-password" i]';
  const passwordField = await findFirstVisible(page.locator(passwordSelector));
  if (passwordField) return true;

  const loginTrigger = await findFirstVisible(
    page.locator('a, button, [role="button"]').filter({
      hasText:
        /log in|login|sign in|zaloguj|zalogować|zaloguj się|inloggen|logga in|connexion|accedi/i,
    })
  );

  if (loginTrigger) {
    await loginTrigger.click();
    if (log) await log('info', 'Clicked login trigger.');
    // We cannot call captureSessionContext here easily without importing context,
    // but better to keep actions pure-ish or passed context.
    // For now omitting session capture inside helper to avoid circular dep,
    // or we assume context is passed if we want.
    // Let's assume the caller handles context capture or we pass the browser context.
    try {
      await page.waitForSelector(passwordSelector, { timeout: 10000 });
    } catch (error) {
      logClientError(error);
      if (log) await log('warning', 'Login form did not appear after clicking trigger.');
    }
    const postClickPassword = await findFirstVisible(page.locator(passwordSelector));
    if (postClickPassword) return true;
  }

  const currentUrl = page.url();
  try {
    const target = new URL(currentUrl);
    const loginUrl = `${target.origin}/login`;
    await page.goto(loginUrl, { waitUntil: 'domcontentloaded', timeout: 20000 });
    if (log) await log('info', 'Navigated to fallback login URL.', { loginUrl });
  } catch (error) {
    logClientError(error);
    if (log) await log('warning', 'Failed to navigate to fallback login URL.');
  }
  const fallbackPassword = await findFirstVisible(page.locator(passwordSelector));
  if (fallbackPassword) return true;
  if (log) await log('warning', 'Login form still not visible after fallback navigation.');
  return false;
};

export const checkForChallenge = async (
  page: Page,
  source: string,
  log?: (level: string, message: string, metadata?: Record<string, unknown>) => Promise<void>,
  stepId?: string | null
): Promise<boolean> => {
  if (!page) return false;
  const html = await page.content();
  const text = await page.evaluate<string>(() => {
    const documentRef = document;
    return documentRef.body?.innerText || documentRef.documentElement?.innerText || '';
  });
  const detectChallenge = (t: string): boolean =>
    /cloudflare|attention required|cf-browser-verification|challenge-platform|cf-turnstile/i.test(
      t
    );
  if (detectChallenge(text) || detectChallenge(html)) {
    if (log) {
      await log('warning', 'Cloudflare challenge detected.', {
        source,
        detail: 'challenge markers in DOM/HTML',
        stepId: stepId ?? null,
      });
    }
    return true;
  }
  return false;
};

import 'server-only';

import { promises as fs } from 'fs';
import path from 'path';

import {
  getAgentAuditLogDelegate,
  getAgentBrowserSnapshotDelegate,
} from '@/features/ai/agent-runtime/store-delegates';
import { getPlaywrightRuntime } from '@/shared/lib/playwright/runtime';

import { toDataUrl } from '../utils';

import type { Browser, BrowserContext, Page, Cookie } from 'playwright';
import { ErrorSystem } from '@/shared/utils/observability/error-system';


type PlaywrightModule = {
  chromium: { launch: (opts: { headless: boolean }) => Promise<Browser> };
  firefox: { launch: (opts: { headless: boolean }) => Promise<Browser> };
  webkit: { launch: (opts: { headless: boolean }) => Promise<Browser> };
};

const asRecord = (value: unknown): Record<string, unknown> | null =>
  value && typeof value === 'object' && !Array.isArray(value)
    ? (value as Record<string, unknown>)
    : null;

const isBrowserType = (
  value: unknown
): value is { launch: (opts: { headless: boolean }) => Promise<Browser> } => {
  const record = asRecord(value);
  return record !== null && typeof record['launch'] === 'function';
};

const isPlaywrightModule = (value: unknown): value is PlaywrightModule => {
  const record = asRecord(value);
  return (
    record !== null &&
    isBrowserType(record['chromium']) &&
    isBrowserType(record['firefox']) &&
    isBrowserType(record['webkit'])
  );
};

const getPlaywright = async (): Promise<PlaywrightModule> => {
  const playwrightModule = getPlaywrightRuntime();
  if (!isPlaywrightModule(playwrightModule)) {
    throw new Error('Playwright runtime is unavailable.');
  }
  return playwrightModule;
};

export const launchBrowser = async (
  browserName: string = 'chromium',
  headless: boolean = true
): Promise<Browser> => {
  const { chromium, firefox, webkit } = await getPlaywright();
  const browserType =
    browserName === 'firefox' ? firefox : browserName === 'webkit' ? webkit : chromium;
  return browserType.launch({ headless });
};

export const createBrowserContext = async (
  browser: Browser,
  runDir: string,
  videoSize: { width: number; height: number } = { width: 1280, height: 720 }
): Promise<BrowserContext> => {
  return browser.newContext({
    viewport: videoSize,
    recordVideo: {
      dir: runDir,
      size: videoSize,
    },
  });
};

export type CaptureOptions = {
  runId: string;
  label: string;
  log?: (level: string, message: string, metadata?: Record<string, unknown>) => Promise<void>;
  activeStepId?: string | null;
};

export const captureSessionContext = async (
  page: Page,
  context: BrowserContext,
  options: CaptureOptions
): Promise<void> => {
  if (!page || !context) return;
  const { runId, label, log, activeStepId } = options;
  const agentAuditLog = getAgentAuditLogDelegate();
  try {
    const cookies = await context.cookies();
    const cookieSummary = cookies.map((cookie: Cookie) => ({
      name: cookie.name,
      domain: cookie.domain,
      path: cookie.path,
      expires: cookie.expires,
      httpOnly: cookie.httpOnly,
      secure: cookie.secure,
      sameSite: cookie.sameSite,
      valueLength: cookie.value?.length ?? 0,
    }));

    const storageSummary = await page.evaluate(() => {
      const localKeys = Object.keys(localStorage ?? {});
      const sessionKeys = Object.keys(sessionStorage ?? {});
      return {
        localKeys,
        sessionKeys,
        localCount: localKeys.length,
        sessionCount: sessionKeys.length,
      };
    });

    if (agentAuditLog) {
      await agentAuditLog.create({
        data: {
          runId,
          level: 'info',
          message: 'Captured session context.',
          metadata: {
            label,
            url: page.url(),
            title: await page.title(),
            cookies: cookieSummary,
            storage: storageSummary,
            stepId: activeStepId ?? null,
          },
        },
      });
    }
    if (log) {
      await log('info', 'Captured session context.', {
        label,
        url: page.url(),
        title: await page.title(),
        cookies: cookieSummary,
        storage: storageSummary,
        stepId: activeStepId ?? null,
      });
    }
  } catch (error) {
    void ErrorSystem.captureException(error);
    if (log) {
      await log('warning', 'Failed to capture session context.', {
        label,
        error: error instanceof Error ? error.message : String(error),
        stepId: activeStepId ?? null,
      });
    }
  }
};

export const captureSnapshot = async (
  page: Page,
  runDir: string,
  options: CaptureOptions
): Promise<{ id: string; domText: string; domHtml: string; url: string }> => {
  if (!page) {
    return { id: '', domText: '', domHtml: '', url: '' };
  }
  const { runId, label, log, activeStepId } = options;
  const agentBrowserSnapshot = getAgentBrowserSnapshotDelegate();
  const domHtml = await page.content();
  const domText = await page.evaluate(
    () => document.body?.innerText || document.documentElement?.innerText || ''
  );
  const title = await page.title();
  const snapshotUrl = page.url();
  const screenshotBuffer = await page.screenshot({ fullPage: true });
  const safeLabel = label.replace(/[^a-z0-9-_]/gi, '_').toLowerCase();
  const screenshotFile = `snapshot-${Date.now()}-${safeLabel}.png`;
  const screenshotPath = path.join(runDir, screenshotFile);
  await fs.writeFile(screenshotPath, screenshotBuffer);
  const viewport = page.viewportSize();

  const snapshot = agentBrowserSnapshot
    ? await agentBrowserSnapshot.create<{ id: string }>({
      data: {
        runId,
        url: snapshotUrl,
        title,
        domHtml,
        domText,
        screenshotData: toDataUrl(screenshotBuffer),
        screenshotPath: screenshotFile,
        stepId: activeStepId ?? null,
        mouseX: null,
        mouseY: null,
        viewportWidth: viewport?.width ?? null,
        viewportHeight: viewport?.height ?? null,
      },
    })
    : null;

  if (log) {
    await log('info', 'Captured DOM snapshot.', {
      label,
      screenshotFile,
      domTextLength: domText.length,
      domHtmlLength: domHtml.length,
      stepId: activeStepId ?? null,
    });
  }

  // Note: collectUiInventory and captureSessionContext calls removed from here
  // to avoid circular dependency and keep functions focused.
  // Caller should call them if needed.

  return { id: snapshot?.id ?? '', domText, domHtml, url: snapshotUrl };
};

import type { Page } from 'playwright';
import { logClientError } from '@/shared/utils/observability/client-error-logger';

export const extractDocumentContent = async (page: Page): Promise<string> => {
  if (!page) return '';
  return page.evaluate(() => {
    const cleanNode = (node: Element): string => {
      const clone = node.cloneNode(true) as HTMLElement;
      const selectors = ['script', 'style', 'nav', 'footer', 'header', 'aside', 'noscript', 'svg'];
      selectors.forEach((sel) => clone.querySelectorAll(sel).forEach((n) => n.remove()));
      return clone.innerText || '';
    };

    const article = document.querySelector('article') ?? document.querySelector('main');
    if (article) return cleanNode(article);

    return cleanNode(document.body);
  });
};

export const extractProductNames = async (page: Page): Promise<string[]> => {
  if (!page) return [];
  return page.evaluate(() => {
    const normalize = (value: string): string => value.replace(/\s+/g, ' ').trim();
    const candidates: string[] = [];
    const seen = new Set<string>();

    const pushName = (value: string | null | undefined): void => {
      if (!value) return;
      const cleaned = normalize(value);
      if (cleaned.length < 3 || cleaned.length > 140) return;
      if (seen.has(cleaned.toLowerCase())) return;
      seen.add(cleaned.toLowerCase());
      candidates.push(cleaned);
    };

    const productSelectors = [
      '[data-product]',
      '[data-product-name]',
      '[data-testid*=\'product\' i]',
      '[itemtype*=\'Product\']',
      '.product',
      '.product-item',
      '.product-card',
      '.product-tile',
      '.product-grid > *',
      '.collection-product',
      '.collection-item',
      '.grid-item',
      'article',
      '[class*=\'product\' i]',
      '[class*=\'card\' i]',
      '[class*=\'grid\' i]',
      '[class*=\'item\' i]',
    ];
    const nameSelectors = [
      '[data-product-name]',
      '[data-testid*=\'title\' i]',
      '[itemprop=\'name\']',
      '.product-title',
      '.product-name',
      '.product-card__title',
      '.card__heading',
      '.product-item__title',
      '.card-title',
      '.card__title',
      '.item-title',
      '.listing-title',
      'h1',
      'h2',
      'h3',
      'h4',
    ];

    const parseJson = (value: string | null): unknown => {
      if (!value) return null;
      try {
        const parsed: unknown = JSON.parse(value);
        return parsed;
      } catch (error) {
        logClientError(error);
        return null;
      }
    };

    const collectFromSchema = (node: unknown): void => {
      if (!node) return;
      if (Array.isArray(node)) {
        node.forEach(collectFromSchema);
        return;
      }
      if (typeof node !== 'object') return;
      const record = node as Record<string, unknown>;
      const typeValue = record['@type'];
      const typeList = Array.isArray(typeValue)
        ? typeValue.filter((value: unknown): value is string => typeof value === 'string')
        : typeof typeValue === 'string'
          ? [typeValue]
          : [];
      const typeNames = typeList.map((value: string) => value.toLowerCase());
      if (
        typeNames.includes('product') ||
        typeNames.includes('productgroup') ||
        typeNames.includes('productmodel')
      ) {
        if (typeof record['name'] === 'string') {
          pushName(record['name']);
        }
      }
      if (typeNames.includes('itemlist') && Array.isArray(record['itemListElement'])) {
        (record['itemListElement'] as unknown[]).forEach((entry: unknown) => {
          if (!entry || typeof entry !== 'object') return;
          const itemRecord = entry as Record<string, unknown>;
          const item = itemRecord['item'];
          if (typeof itemRecord['name'] === 'string') {
            pushName(itemRecord['name']);
          }
          if (item && typeof item === 'object') {
            const itemObj = item as Record<string, unknown>;
            if (typeof itemObj['name'] === 'string') {
              pushName(itemObj['name']);
            }
          }
        });
      }
      if (record['@graph']) {
        collectFromSchema(record['@graph']);
      }
    };

    for (const selector of productSelectors) {
      document.querySelectorAll(selector).forEach((node: Element) => {
        if (!(node instanceof HTMLElement)) return;
        const element = node;
        for (const nameSelector of nameSelectors) {
          const nameNode = element.querySelector<HTMLElement>(nameSelector);
          if (nameNode?.innerText) {
            pushName(nameNode.innerText);
            break;
          }
        }
        if (element.getAttribute('data-product-name')) {
          pushName(element.getAttribute('data-product-name'));
        }
        const img = element.querySelector<HTMLImageElement>('img[alt]');
        if (img?.alt) {
          pushName(img.alt);
        }
      });
    }

    document
      .querySelectorAll('a[href*=\'/product\' i], a[href*=\'product\' i]')
      .forEach((link: Element) => {
        if (!(link instanceof HTMLElement)) return;
        const text = link.innerText;
        if (text) pushName(text);
      });

    document.querySelectorAll('h2, h3, h4').forEach((heading: Element) => {
      if (!(heading instanceof HTMLElement)) return;
      pushName(heading.innerText);
    });

    document.querySelectorAll('script[type=\'application/ld+json\']').forEach((script: Element) => {
      const parsed = parseJson(script.textContent);
      if (parsed) {
        collectFromSchema(parsed);
      }
    });

    return candidates;
  });
};

export const extractProductNamesFromSelectors = async (
  page: Page,
  selectors: string[]
): Promise<string[]> => {
  if (!page || selectors.length === 0) return [];
  return page.evaluate((selectorsParam: string[]) => {
    const normalize = (value: string): string => value.replace(/\s+/g, ' ').trim();
    const candidates: string[] = [];
    const seen = new Set<string>();

    const pushName = (value: string | null | undefined): void => {
      if (!value) return;
      const cleaned = normalize(value);
      if (cleaned.length < 3 || cleaned.length > 140) return;
      if (seen.has(cleaned.toLowerCase())) return;
      seen.add(cleaned.toLowerCase());
      candidates.push(cleaned);
    };

    selectorsParam.forEach((selector: string) => {
      document.querySelectorAll(selector).forEach((node: Element) => {
        if (!(node instanceof HTMLElement)) return;
        const element = node;
        const text = element.innerText || element.textContent;
        if (text) pushName(text);
        if (element.getAttribute('data-product-name')) {
          pushName(element.getAttribute('data-product-name'));
        }
        const img = element.querySelector<HTMLImageElement>('img[alt]');
        if (img?.alt) {
          pushName(img.alt);
        }
      });
    });

    return candidates;
  }, selectors);
};

export const extractEmailsFromDom = async (page: Page): Promise<string[]> => {
  if (!page) return [];
  return page.evaluate(() => {
    const emails = new Set<string>();
    document.querySelectorAll('a[href^=\'mailto:\']').forEach((link: Element) => {
      if (!(link instanceof HTMLAnchorElement)) return;
      const href = link.getAttribute('href') || '';
      const email = href
        .replace(/^mailto:/i, '')
        .split('?')[0]
        ?.trim();
      if (email) emails.add(email);
    });
    document
      .querySelectorAll('[data-email], [data-mail], [data-contact]')
      .forEach((node: Element) => {
        if (!(node instanceof HTMLElement)) return;
        const element = node;
        const value =
          element.getAttribute('data-email') ||
          element.getAttribute('data-mail') ||
          element.getAttribute('data-contact') ||
          '';
        if (value.includes('@')) {
          value
            .split(/[,\s]+/)
            .map((item: string) => item.trim())
            .filter(Boolean)
            .forEach((item: string) => emails.add(item));
        }
      });
    return Array.from(emails);
  });
};

export const waitForProductContent = async (page: Page): Promise<void> => {
  if (!page) return;
  const productSelectors = [
    '[data-product]',
    '[data-product-name]',
    '[data-testid*=\'product\' i]',
    '[itemtype*=\'Product\']',
    '.product',
    '.product-item',
    '.product-card',
    '.product-tile',
    '.product-grid > *',
    '.collection-product',
    '.collection-item',
    '.grid-item',
    'article',
    '[class*=\'product\' i]',
    '[class*=\'card\' i]',
    '[class*=\'grid\' i]',
    '[class*=\'item\' i]',
  ];
  try {
    await page.waitForLoadState('networkidle', { timeout: 15000 });
  } catch (error) {
    logClientError(error);

    // Ignore network idle timeouts.
  }
  try {
    await Promise.race(
      productSelectors.map((selector: string) => page.waitForSelector(selector, { timeout: 4000 }))
    );
  } catch (error) {
    logClientError(error);

    // Ignore if no product selectors appear quickly.
  }
};

export const autoScroll = async (page: Page): Promise<void> => {
  if (!page) return;
  await page.evaluate(async () => {
    const totalHeight = document.body.scrollHeight;
    const distance = Math.min(800, window.innerHeight || 800);
    let current = 0;
    while (current < totalHeight) {
      window.scrollBy(0, distance);
      current += distance;
      await new Promise((resolve: (value: unknown) => void) => setTimeout(resolve, 250));
    }
    window.scrollTo(0, 0);
  });
};

export const findProductListingUrls = async (page: Page): Promise<string[]> => {
  if (!page) return [];
  return page.evaluate(() => {
    const keywords = /(shop|store|product|collection|catalog|menu|shopall|shop-all|merch)/i;
    const origin = location.origin;
    const urls = new Set<string>();
    document.querySelectorAll('a[href]').forEach((link: Element) => {
      const href = (link as HTMLAnchorElement).href;
      const text = (link as HTMLElement).innerText || '';
      if (!href?.startsWith(origin)) return;
      if (keywords.test(href) || keywords.test(text)) {
        urls.add(href);
      }
    });
    return Array.from(urls).slice(0, 5);
  });
};

import type { UiElement, UiInventory } from '@/shared/contracts/agent-runtime';
import { getAgentAuditLogDelegate } from '@/features/ai/agent-runtime/store-delegates';

import type { Page } from 'playwright';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


export type { UiElement, UiInventory };

export const collectUiInventory = async (
  page: Page,
  runId: string,
  label: string,
  log?: (level: string, message: string, metadata?: Record<string, unknown>) => Promise<void>,
  activeStepId?: string | null
): Promise<UiInventory | null> => {
  if (!page) return null;
  const agentAuditLog = getAgentAuditLogDelegate();
  try {
    const uiInventory = await page.evaluate<UiInventory>(() => {
      const documentRef = document;

      const cssPath = (el: Element): string | null => {
        if (!(el instanceof Element)) return null;
        if (el.id) return `#${CSS.escape(el.id)}`;
        const parts: string[] = [];
        let node: Element | null = el;
        while (node !== null) {
          if (node.nodeType !== 1 || node === documentRef.documentElement) break;
          const currentNode: Element = node;
          let part = currentNode.tagName.toLowerCase();
          const name = currentNode.getAttribute('name');
          const dataTest =
            currentNode.getAttribute('data-testid') ||
            currentNode.getAttribute('data-test') ||
            currentNode.getAttribute('data-qa');
          if (name) {
            part += `[name="${name.replace(/"/g, '\\"')}"]`;
          } else if (dataTest) {
            part += `[data-testid="${dataTest.replace(/"/g, '\\"')}"]`;
          }
          const parent = currentNode.parentElement;
          if (parent) {
            const siblings = Array.from(parent.children as HTMLCollectionOf<Element>, (child) => child);
            const matchingSiblings = siblings.filter((child) => child.tagName === currentNode.tagName);
            if (matchingSiblings.length > 1) {
              part += `:nth-of-type(${matchingSiblings.indexOf(currentNode) + 1})`;
            }
          }
          parts.unshift(part);
          node = currentNode.parentElement;
        }
        return parts.join(' > ');
      };

      const visible = (el: Element): boolean => (el as HTMLElement).offsetParent !== null;
      const describe = (el: Element): UiElement => ({
        tag: el.tagName.toLowerCase(),
        id: (el as HTMLElement).id || null,
        name: (el as HTMLInputElement).name || null,
        type: (el as HTMLInputElement).type || null,
        text: (el as HTMLElement).innerText?.trim().slice(0, 160) || null,
        placeholder: (el as HTMLInputElement).placeholder || null,
        ariaLabel: el.getAttribute('aria-label'),
        role: el.getAttribute('role'),
        selector: cssPath(el),
      });

      const cap = 200;
      const inputs = Array.from(
        documentRef.querySelectorAll('input, textarea, select')
      )
        .filter(visible)
        .map(describe);
      const buttons = Array.from(
        documentRef.querySelectorAll('button, input[type=\'submit\'], input[type=\'button\']')
      )
        .filter(visible)
        .map(describe);
      const links = Array.from(documentRef.querySelectorAll('a[href]'))
        .filter(visible)
        .map((el: Element) => ({
          ...describe(el),
          href: (el as HTMLAnchorElement).href,
        }));
      const headings = Array.from(
        documentRef.querySelectorAll('h1, h2, h3, h4, h5, h6')
      )
        .filter(visible)
        .map(describe);
      const forms = Array.from(documentRef.querySelectorAll('form') as NodeListOf<Element>)
        .filter(visible)
        .map((el: Element) => ({
          ...describe(el),
          action: (el as HTMLFormElement).action || null,
          method: (el as HTMLFormElement).method || null,
        }));

      const truncated = {
        inputs: inputs.length > cap,
        buttons: buttons.length > cap,
        links: links.length > cap,
        headings: headings.length > cap,
        forms: forms.length > cap,
      };

      return {
        url: documentRef.location.href,
        title: documentRef.title,
        counts: {
          inputs: inputs.length,
          buttons: buttons.length,
          links: links.length,
          headings: headings.length,
          forms: forms.length,
        },
        inputs: inputs.slice(0, cap),
        buttons: buttons.slice(0, cap),
        links: links.slice(0, cap),
        headings: headings.slice(0, cap),
        forms: forms.slice(0, cap),
        truncated,
      };
    });
    if (log) {
      await log('info', 'Captured UI inventory.', {
        label,
        stepId: activeStepId ?? null,
        uiInventory,
      });
    }
    await agentAuditLog?.create({
      data: {
        runId,
        level: 'info',
        message: 'Captured UI inventory.',
        metadata: {
          label,
          stepId: activeStepId ?? null,
          uiInventory,
        },
      },
    });
    return uiInventory;
  } catch (error) {
    logClientError(error);
    if (log) {
      await log('warning', 'Failed to capture UI inventory.', {
        label,
        stepId: activeStepId ?? null,
        error: error instanceof Error ? error.message : String(error),
      });
    }
  }
  return null;
};

import 'server-only';

import { randomUUID } from 'crypto';
import { promises as fs } from 'fs';
import path from 'path';

import {
  getAgentBrowserLogDelegate,
  getAgentBrowserSnapshotDelegate,
  getChatbotAgentRunDelegate,
} from '@/features/ai/agent-runtime/store-delegates';
import type { InputJsonValue } from '@/shared/contracts/json';
import { ErrorSystem } from '@/shared/utils/observability/error-system';

import {
  launchBrowser,
  createBrowserContext,
  captureSnapshot,
  captureSessionContext,
} from './playwright/browser';
import { collectUiInventory } from './playwright/inventory';
import { extractTargetUrl } from './utils';

import type { AgentControlAction, AgentToolResult } from './tool-types';
import type { Browser, BrowserContext, Page } from 'playwright';

type BrowserControlRunRecord = {
  prompt: string;
  agentBrowser: string | null;
  runHeadless: boolean | null;
};

export async function runAgentBrowserControl({
  runId,
  action,
  url,
  stepId,
  stepLabel,
}: {
  runId: string;
  action: AgentControlAction;
  url?: string | undefined;
  stepId?: string | undefined;
  stepLabel?: string | undefined;
}): Promise<AgentToolResult> {
  const debugEnabled = process.env['DEBUG_CHATBOT'] === 'true';
  const chatbotAgentRun = getChatbotAgentRunDelegate();
  const agentBrowserLog = getAgentBrowserLogDelegate();
  const agentBrowserSnapshot = getAgentBrowserSnapshotDelegate();
  if (!agentBrowserLog || !agentBrowserSnapshot) {
    void ErrorSystem.logWarning('[chatbot][agent][tool] Agent browser tables not initialized.', {
      service: 'agent-control',
      runId,
    });
    return {
      ok: false,
      error: 'Agent browser storage is unavailable.',
    };
  }

  let launch: Browser | null = null;
  let context: BrowserContext | null = null;
  try {
    const run = chatbotAgentRun
      ? await chatbotAgentRun.findUnique<BrowserControlRunRecord>({ where: { id: runId } })
      : null;
    if (!run) {
      return { ok: false, error: 'Agent run not found.' };
    }

    const runDir = path.join(process.cwd(), 'tmp', 'chatbot-agent', runId);
    await fs.mkdir(runDir, { recursive: true });

    const activeStepId = stepId ?? null;
    const log = async (
      level: string,
      message: string,
      metadata?: Record<string, unknown>
    ): Promise<void> => {
      await agentBrowserLog.create({
        data: {
        runId,
        stepId: activeStepId,
        level,
        message,
        metadata: metadata as InputJsonValue,
      },
    });
    };

    const latestSnapshot = await agentBrowserSnapshot.findFirst<{ url: string }>({
      where: { runId },
      orderBy: { createdAt: 'desc' },
    });

    const fallbackUrl = extractTargetUrl(run.prompt) ?? null;
    const latestUrl =
      latestSnapshot?.url && latestSnapshot.url !== 'about:blank' ? latestSnapshot.url : null;
    const targetUrl = action === 'goto' && url?.trim() ? url.trim() : (latestUrl ?? fallbackUrl);

    if (!targetUrl && action !== 'snapshot') {
      return { ok: false, error: 'No target URL available for control action.' };
    }

    launch = await launchBrowser(run.agentBrowser ?? 'chromium', run.runHeadless ?? true);
    context = await createBrowserContext(launch, runDir);
    const page: Page = await context.newPage();

    await log('info', 'Agent control action started.', {
      action,
      url: targetUrl,
      browser: run.agentBrowser || 'chromium',
    });

    if (targetUrl) {
      await page.goto(targetUrl, { waitUntil: 'domcontentloaded', timeout: 30000 });
      if (action === 'reload') {
        await page.reload({ waitUntil: 'domcontentloaded', timeout: 30000 });
      }
    } else {
      await page.setContent(
        '<html><head><title>Agent preview</title></head><body><h1>No target URL</h1></body></html>'
      );
    }

    const safeLabel = stepLabel ? `step-${stepLabel}` : `control-${action}`;

    const createdSnapshot = await captureSnapshot(page, runDir, {
      runId,
      label: safeLabel,
      log,
      activeStepId,
    });

    // Re-implemented UI inventory and session capture to use shared functions if possible,
    // or keep local if needed. Since I exported them, I can use them.
    await collectUiInventory(page, runId, safeLabel, log, activeStepId);
    await captureSessionContext(page, context, {
      runId,
      label: safeLabel,
      log,
      activeStepId,
    });

    const logCount = await agentBrowserLog.count({ where: { runId } });

    // We need to return snapshotId, captureSnapshot doesn't return ID directly but creates it.
    // I should have made captureSnapshot return the object.
    // For now I'll query it or just rely on latest.
    const freshSnapshot = await agentBrowserSnapshot.findFirst<{ id: string }>({
      where: { runId },
      orderBy: { createdAt: 'desc' },
    });

    return {
      ok: true,
      output: {
        url: createdSnapshot.url,
        snapshotId: freshSnapshot?.id ?? null,
        logCount,
      },
    };
  } catch (error) {
    void ErrorSystem.captureException(error);
    const errorId = randomUUID();
    const message = error instanceof Error ? error.message : 'Control action failed.';

    try {
      await ErrorSystem.captureException(error, {
        service: 'agent-control',
        action: 'runAgentBrowserControl',
        runId,
        errorId,
        requestedAction: action,
      });
    } catch (logError) {
      void ErrorSystem.captureException(logError);
      if (debugEnabled) {
        const { logger } = await import('@/shared/utils/logger');
        logger.error('[chatbot][agent][control] Failed (and logging failed)', logError, {
          runId,
          errorId,
          error,
        });
      }
    }

    try {
      await agentBrowserLog.create({
        data: {
          runId,
          level: 'error',
          message,
          metadata: { errorId },
        },
      });
    } catch (error) {
      void ErrorSystem.captureException(error);

      // ignore logging failures
    }
    return { ok: false, error: message, errorId };
  } finally {
    if (context) {
      await context.close();
    }
    if (launch) {
      await launch.close();
    }
  }
}

