const enforceRobotsPolicy = async (
    url: string,
    ignoreRobotsTxt: boolean,
    log: any
): Promise<boolean> => {
    if (ignoreRobotsTxt) return true;
    if (url === '' || url === 'about:blank') return true;
    const robots = await loadRobotsTxt(url);
    if (!robots.ok) {
      await log('warning', 'Robots.txt unavailable; proceeding.', {
        url,
        status: robots.status,
        error: robots.error ?? null,
      });
      return true;
    }
    const parsed = parseRobotsRules(robots.content);
    const rules = parsed.get('*') ?? [];
    const pathName = new URL(url).pathname || '/';
    const evaluation = evaluateRobotsRules(rules, pathName);
    if (!evaluation.allowed) {
      await log('warning', 'Blocked by robots.txt.', {
        url,
        path: pathName,
        matchedRule: evaluation.matchedRule,
      });
      return false;
    }
    return true;
};

export async function runAgentTool(
  request: AgentToolRequest,
  injectedBrowser?: Browser,
  injectedContext?: BrowserContext
): Promise<AgentToolResult> {
  let contextData: Awaited<ReturnType<typeof resolveToolContext>>;
  try {
    contextData = await resolveToolContext({ request, injectedBrowser, injectedContext });
  } catch (error) {
    logClientError(error);
    return { ok: false, error: error instanceof Error ? error.message : String(error) };
  }

  const {
    runId,
    prompt,
    stepId,
    stepLabel,
    targetUrl,
    targetHostname,
    runDir: _runDir,
    launch,
    context,
    config,
  } = contextData;
  const {
    resolvedModel,
    resolvedSearchProvider,
    ignoreRobotsTxt,
    memoryKey,
    memoryValidationModel,
    memorySummarizationModel,
    outputNormalizationModel,
    toolRouterModel,
    selectorInferenceModel,
    extractionValidationModel,
  } = config;

  const log = createToolLogger({
    runId,
    stepId: stepId ?? null,
    model: resolvedModel,
    outputNormalizationModel: outputNormalizationModel ?? '',
    prompt: prompt ?? '',
  });

  const activeStepId = stepId ?? null;
// ... (rest of function with updated enforceRobotsPolicy calls)

  let page: Page | null;
  if (injectedContext && context.pages().length > 0) {
    page = context.pages()[0] ?? null;
    if (page) {
      await page.bringToFront().catch(() => {});
      page.removeAllListeners('console');
      page.removeAllListeners('pageerror');
      page.removeAllListeners('requestfailed');
      page.removeAllListeners('response');
    }
  } else {
    page = await context.newPage();
  }

  if (!page) {
    throw new Error('Failed to initialize Playwright page.');
  }

  // Page event handlers
  page.on('console', async (msg: ConsoleMessage): Promise<void> => {
    const type = msg.type();
    await log(type === 'error' ? 'error' : 'info', `[console:${type}] ${msg.text()}`);
  });
  page.on('pageerror', async (err: Error): Promise<void> => {
    await log('error', `Page error: ${err.message}`);
  });
  page.on('requestfailed', async (req: Request): Promise<void> => {
    await log('warning', `Request failed: ${req.url()}`, {
      error: req.failure()?.errorText,
    });
  });

  const detectionState = { cloudflareDetected: false };
  const flagCloudflare = async (source: string, detail?: string): Promise<void> => {
    if (detectionState.cloudflareDetected) return;
    detectionState.cloudflareDetected = true;
    await log('warning', 'Cloudflare challenge detected.', {
      source,
      detail,
      stepId: stepId ?? null,
    });
  };
  page.on('response', async (res: Response): Promise<void> => {
    const status = res.status();
    if (status === 403) {
      const url = res.url();
      if (/cloudflare|cdn-cgi|login\.baselinker\.com/i.test(url)) {
        await flagCloudflare('response-403', url);
      }
    }
  });

  await log('info', 'Playwright tool started.', {
    browser: request.input.browser || 'chromium',
    runHeadless: request.input.runHeadless ?? true,
    targetUrl,
  });

  let finalUrl: string;

  const llmContext: AgentLlmContext = {
    model: resolvedModel,
    runId,
    log,
    activeStepId,
    stepLabel: stepLabel || undefined,
  };
  const toolLlmContext = {
    ...llmContext,
    model: toolRouterModel ?? resolvedModel,
  };

  try {
    const searchFirstDecision = await decideSearchFirstWithLLM(
      toolLlmContext,
      prompt ?? '',
      targetUrl,
      hasExplicitUrl(prompt),
      memoryKey,
      memoryValidationModel,
      memorySummarizationModel
    );

    let navigatedViaSearch = false;
    if (targetUrl !== 'about:blank') {
      if (searchFirstDecision?.useSearchFirst) {
        const query = searchFirstDecision.query;
        const results = query ? await fetchSearchResults(query, resolvedSearchProvider, log) : [];
        const allowedResults = targetHostname
          ? results.filter((result: { url: string }) => isAllowedUrl(result.url, targetHostname))
          : results;

        if (targetHostname && allowedResults.length === 0) {
          await log('warning', 'Search-first returned no allowed results.', {
            stepId: activeStepId ?? null,
            query,
            targetHostname,
          });
        }

        const picked =
          query && allowedResults.length
            ? await pickSearchResultWithLLM(toolLlmContext, query, prompt ?? '', allowedResults)
            : null;

        const resolvedPicked =
          picked && (!targetHostname || isAllowedUrl(picked, targetHostname)) ? picked : null;

        if (picked && !resolvedPicked) {
          await log('warning', 'Search-first ignored disallowed URL.', {
            stepId: activeStepId ?? null,
            query,
            url: picked,
            targetHostname,
          });
        }

        const fallback = resolvedPicked || (allowedResults.length ? allowedResults[0]?.url : null);

        if (fallback) {
          if (!(await enforceRobotsPolicy(fallback, ignoreRobotsTxt, log))) {
            return { ok: false, error: 'Blocked by robots.txt.' };
          }
          await page.goto(fallback, {
            waitUntil: 'domcontentloaded',
            timeout: 30000,
          });
          navigatedViaSearch = true;
        } else {
          await log('warning', 'Search-first produced no results; falling back.', {
            stepId: activeStepId ?? null,
            query,
          });
        }
      }

      if (!navigatedViaSearch) {
        if (!(await enforceRobotsPolicy(targetUrl, ignoreRobotsTxt, log))) {
          return { ok: false, error: 'Blocked by robots.txt.' };
        }
        try {
          await page.goto(targetUrl, {
            waitUntil: 'domcontentloaded',
            timeout: 30000,
          });
        } catch (error) {
          logClientError(error);
          await log('warning', 'Direct navigation failed; attempting search.', {
            stepId: activeStepId ?? null,
            url: targetUrl,
            error: error instanceof Error ? error.message : String(error),
          });

          const query =
            (await buildSearchQueryWithLLM(toolLlmContext, prompt ?? '')) ?? prompt ?? '';
          let searchUrl: string | null = null;
          if (query) {
            const results = await fetchSearchResults(query, resolvedSearchProvider, log);
            if (results.length > 0) {
              const allowedResults = targetHostname
                ? results.filter((result: { url: string }) =>
                  isAllowedUrl(result.url, targetHostname)
                )
                : results;

              if (targetHostname && allowedResults.length === 0) {
                await log('warning', 'Search escalation returned no allowed results.', {
                  stepId: activeStepId ?? null,
                  query,
                  targetHostname,
                });
              } else {
                const picked = await pickSearchResultWithLLM(
                  toolLlmContext,
                  query,
                  prompt ?? '',
                  allowedResults
                );
                const resolvedPicked =
                  picked && (!targetHostname || isAllowedUrl(picked, targetHostname))
                    ? picked
                    : null;
                if (picked && !resolvedPicked) {
                  await log('warning', 'Search escalation ignored disallowed URL.', {
                    stepId: activeStepId ?? null,
                    query,
                    url: picked,
                    targetHostname,
                  });
                }
                searchUrl = (resolvedPicked || allowedResults[0]?.url) ?? null;
                if (searchUrl) {
                  await log('info', 'Search escalation selected URL.', {
                    stepId: activeStepId ?? null,
                    query,
                    url: searchUrl,
                  });
                }
              }
            }
          }

          if (searchUrl) {
            if (!(await enforceRobotsPolicy(searchUrl, ignoreRobotsTxt, log))) {
              return { ok: false, error: 'Blocked by robots.txt.' };
            }
            await page.goto(searchUrl, {
              waitUntil: 'domcontentloaded',
              timeout: 30000,
            });
          } else {
            throw error;
          }
        }
      }
    }

    finalUrl = page.url();
    await dismissConsent(page, 'auto', log, activeStepId).catch(() => {});

    const challengeDetected = await checkForChallenge(page, 'auto', log, activeStepId);
    if (challengeDetected) {
      await flagCloudflare('challenge-detected', 'Challenge detected on page');
    }

    const extractionResult = await runExtractionRequest({
      page,
      prompt: prompt ?? '',
      runId,
      runDir: _runDir,
      activeStepId,
      stepLabel: stepLabel || undefined,
      targetHostname,
      domText: '', // Will be extracted if empty
      finalUrl,
      llmContext,
      resolvedModel,
      selectorInferenceModel: selectorInferenceModel ?? null,
      outputNormalizationModel: outputNormalizationModel ?? null,
      extractionValidationModel: extractionValidationModel ?? null,
      log,
    });

    if (parseExtractionRequest(prompt) && !extractionResult) {
      throw new Error('Extraction failed to produce a result.');
    }

    const snapshot = await captureSnapshot(page, _runDir, { runId, label: 'auto', log, activeStepId });

    return {
      ok: extractionResult ? extractionResult.ok : true,
      error: extractionResult?.error,
      output: {
        url: finalUrl,
        domText: safeText(snapshot.domText),
        snapshotId: snapshot.id,
        logCount: 0,
        cloudflareDetected: detectionState.cloudflareDetected,
        ...(extractionResult?.output ?? {}),
      },
    };
  } catch (error) {
    logClientError(error);
    const errorId = randomUUID();
    const message = error instanceof Error ? error.message : String(error);
    await log('error', `Tool execution failed: ${message}`, { errorId });

    let snapshotId: string | null = null;
    if (page) {
      const errorSnapshot = await (
        captureSnapshot(page, _runDir, { runId, label: 'error', log, activeStepId }) as Promise<{
          id: string;
        } | null>
      ).catch(() => null);
      snapshotId = errorSnapshot?.id ?? null;
    }

    return {
      ok: false,
      error: message,
      errorId,
      output: {
        url: page?.url(),
        snapshotId,
        cloudflareDetected: detectionState.cloudflareDetected,
      },
    };
  } finally {
    if (!injectedContext && context) {
      await context.close().catch(() => {});
    }
    if (!injectedBrowser && !injectedContext && launch) {
      await launch.close().catch(() => {});
    }
  }
}

import type { InputJsonValue } from '@/shared/contracts/json';
import { getAgentBrowserLogDelegate } from '@/features/ai/agent-runtime/store-delegates';

import { normalizeExtractionItemsWithLLM } from '../llm';

export function createToolLogger(args: {
  runId: string;
  stepId: string | null;
  model: string;
  outputNormalizationModel: string;
  prompt: string;
}) {
  const { runId, stepId, model, outputNormalizationModel, prompt } = args;
  const agentBrowserLog = getAgentBrowserLogDelegate();

  const log = async (
    level: string,
    message: string,
    metadata?: Record<string, unknown>
  ): Promise<void> => {
    const normalizeLogMetadata = async (
      payload?: Record<string, unknown>
    ): Promise<Record<string, unknown> | undefined> => {
      if (!payload || !outputNormalizationModel) return payload;
      const extractionType = payload['extractionType'];
      if (extractionType !== 'product_names' && extractionType !== 'emails') {
        return payload;
      }

      const normalizeField = async (key: string): Promise<void> => {
        const value = payload[key];
        if (!Array.isArray(value)) return;
        const items = value.filter((item: unknown): item is string => typeof item === 'string');
        if (items.length === 0) return;
        const typedExtractionType: 'product_names' | 'emails' = extractionType;
        const normalized = await normalizeExtractionItemsWithLLM(
          {
            model,
            runId,
            log: async () => {},
          },
          {
            prompt,
            extractionType: typedExtractionType,
            items,
            normalizationModel: outputNormalizationModel,
          }
        );
        payload[key] = normalized;
      };

      await Promise.all([
        normalizeField('items'),
        normalizeField('names'),
        normalizeField('extractedItems'),
        normalizeField('extractedNames'),
        normalizeField('acceptedItems'),
        normalizeField('rejectedItems'),
      ]);
      return payload;
    };

    const normalizedMetadata = await normalizeLogMetadata(metadata ? { ...metadata } : undefined);

    if (!agentBrowserLog) {
      return;
    }

    await agentBrowserLog.create({
      data: {
        runId,
        stepId,
        level,
        message,
        metadata: normalizedMetadata as InputJsonValue,
      },
    });
  };

  return log;
}

import { logClientError } from '@/shared/utils/observability/client-error-logger';

export const toDataUrl = (buffer: Buffer): string => `data:image/png;base64,${buffer.toString('base64')}`;

export const safeText = (value: string | null | undefined): string => value ?? '';

export const extractTargetUrl = (prompt?: string): string | null => {
  if (prompt === undefined || prompt === null || prompt === '') return null;
  const urlMatch = prompt.match(/https?:\/\/[^\s)]+/i);
  if (urlMatch !== null) return urlMatch[0];
  const domainMatch = prompt.match(/\b([a-z0-9-]+\.)+[a-z]{2,}\b/i);
  if (domainMatch !== null) {
    return `https://${domainMatch[0]}`;
  }
  if (/base\.com/i.test(prompt)) {
    return 'https://base.com';
  }
  return null;
};

export const hasExplicitUrl = (prompt?: string): boolean =>
  prompt !== undefined && prompt !== null && prompt !== '' && Boolean(prompt.match(/https?:\/\/[^\s)]+/i));

export const getTargetHostname = (prompt?: string): string | null => {
  const url = extractTargetUrl(prompt);
  if (url === null) return null;
  try {
    return new URL(url).hostname.replace(/^www\./i, '');
  } catch (error) {
    logClientError(error);
    return null;
  }
};

export const isAllowedUrl = (url: string, targetHostname: string | null): boolean => {
  if (targetHostname === null || targetHostname === '') return true;
  try {
    const hostname = new URL(url).hostname.replace(/^www\./i, '');
    return hostname === targetHostname || hostname.endsWith(`.${targetHostname}`);
  } catch (error) {
    logClientError(error);
    return false;
  }
};

export const normalizeProductNames = (items: string[]): string[] => {
  const seen = new Set<string>();
  const uiNoise =
    /^(add to cart|quick view|view details|view product|choose options|select options|in stock|out of stock|sold out|sale|new|buy now|learn more|load more|show more|filters?|sort by)$/i;
  return items
    .map((item: string) => item.replace(/\s+/g, ' ').trim())
    .filter((item: string) => item !== '')
    .filter((item: string) => /[a-z]/i.test(item))
    .filter((item: string) => !/^[a-f0-9]{16,}$/i.test(item))
    .filter((item: string) => !/^[a-f0-9]{32,}$/i.test(item))
    .filter((item: string) => !/^\$?\d+(?:\.\d+)?$/.test(item))
    .filter((item: string) => !uiNoise.test(item))
    .filter((item: string) => {
      const key = item.toLowerCase();
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    });
};

export const normalizeEmailCandidates = (items: string[]): string[] => {
  const seen = new Set<string>();
  const cleaned = items
    .map((item: string) => item.trim().toLowerCase())
    .filter((item: string) => item !== '')
    .filter((item: string) => /^[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}$/.test(item));
  return cleaned.filter((item: string) => {
    if (seen.has(item)) return false;
    seen.add(item);
    return true;
  });
};

export const loadRobotsTxt = async (
  url: string
): Promise<{ ok: boolean; status: number | null; content: string; error?: string }> => {
  try {
    const target = new URL(url);
    const robotsUrl = `${target.origin}/robots.txt`;
    const response = await fetch(robotsUrl, { method: 'GET' });
    if (!response.ok) {
      return { ok: false, status: response.status, content: '' };
    }
    const content = await response.text();
    return { ok: true, status: response.status, content };
  } catch (error) {
    logClientError(error);
    return {
      ok: false,
      status: null,
      content: '',
      error: error instanceof Error ? error.message : String(error),
    };
  }
};

export const parseRobotsRules = (
  robotsTxt: string
): Map<string, Array<{ type: 'allow' | 'disallow'; path: string }>> => {
  const rules = new Map<string, Array<{ type: 'allow' | 'disallow'; path: string }>>();
  let currentAgents: string[] = [];
  const lines = robotsTxt.split(/\r?\n/);
  for (const rawLine of lines) {
    const line = rawLine.split('#')[0]?.trim() ?? '';
    if (line === '') continue;
    const [rawKey, ...rest] = line.split(':');
    const key = rawKey?.trim().toLowerCase() ?? '';
    const value = rest.join(':').trim();
    if (key === '') continue;
    if (key === 'user-agent') {
      const agent = value.toLowerCase();
      currentAgents = agent !== '' ? [agent] : [];
      for (const entry of currentAgents) {
        if (!rules.has(entry)) {
          rules.set(entry, []);
        }
      }
      continue;
    }
    if (key === 'allow' || key === 'disallow') {
      if (currentAgents.length === 0) continue;
      for (const agent of currentAgents) {
        const list = rules.get(agent) ?? [];
        list.push({ type: key, path: value });
        rules.set(agent, list);
      }
    }
  }
  return rules;
};

export const evaluateRobotsRules = (
  rules: Array<{ type: 'allow' | 'disallow'; path: string }>,
  path: string
): { allowed: boolean; matchedRule: { type: 'allow' | 'disallow'; path: string } | null } => {
  let bestMatch: { type: 'allow' | 'disallow'; path: string } | null = null;
  for (const rule of rules) {
    if (rule.path === '') {
      if (rule.type === 'allow' && bestMatch === null) {
        bestMatch = rule;
      }
      continue;
    }
    if (path.startsWith(rule.path)) {
      if (bestMatch === null || rule.path.length > bestMatch.path.length) {
        bestMatch = rule;
      } else if (rule.path.length === (bestMatch?.path.length ?? 0) && rule.type === 'allow') {
        bestMatch = rule;
      }
    }
  }
  if (bestMatch === null) return { allowed: true, matchedRule: null };
  return {
    allowed: bestMatch.type !== 'disallow',
    matchedRule: bestMatch,
  };
};

export const parseCredentials = (
  prompt?: string
): { email?: string; username?: string; password?: string } | null => {
  if (prompt === undefined || prompt === null || prompt === '') return null;
  const emailMatch = prompt.match(/email\s*[:=]\s*([^\s]+)/i);
  const userMatch = prompt.match(/(?:username|user|login)\s*[:=]\s*([^\s]+)/i);
  const passMatch = prompt.match(/(?:password|pass|pwd)\s*[:=]\s*([^\s]+)/i);
  const email = emailMatch?.[1];
  const username = userMatch?.[1];
  const password = passMatch?.[1];
  if (password === undefined || (email === undefined && username === undefined)) return null;
  return {
    ...(email !== undefined ? { email } : {}),
    ...(username !== undefined ? { username } : {}),
    password,
  };
};

export const parseExtractionRequest = (
  prompt?: string
): { type: 'product_names' | 'emails' | 'batch_image'; count: number | null } | null => {
  if (prompt === undefined || prompt === null || prompt === '') return null;

  if (/generate\s+images/i.test(prompt)) {
    const countMatch = prompt.match(/(\d+)\s*images/i);
    return { type: 'batch_image', count: countMatch !== null ? Number(countMatch[1]) : 1 };
  }

  const taskTypeHint = /task type:\s*extract_info/i.test(prompt);
  const wantsExtraction = taskTypeHint || /(extract|collect|find|list|get)\b/i.test(prompt);
  if (/task type:\s*web_task/i.test(prompt) && !wantsExtraction) return null;
  if (!wantsExtraction) return null;
  const isProduct = /product/i.test(prompt);
  const isEmail = /email/i.test(prompt);
  const countMatch = prompt.match(/(\d+)\s*(?:products?|product names?|emails?)/i);
  const count = countMatch !== null ? Number(countMatch[1]) : null;
  if (isEmail) {
    return { type: 'emails', count };
  }
  if (isProduct) {
    return { type: 'product_names', count };
  }
  if (taskTypeHint) {
    return { type: 'emails', count };
  }
  return null;
};

export const buildEvidenceSnippets = (
  items: string[],
  domText: string
): Array<{ item: string; snippet: string }> => {
  const evidence: Array<{ item: string; snippet: string }> = [];
  if (domText === '') return evidence;
  const lowerText = domText.toLowerCase();
  for (const item of items) {
    const query = item.trim().toLowerCase();
    if (query === '') continue;
    let index = lowerText.indexOf(query);
    let occurrences = 0;
    while (index !== -1 && occurrences < 2) {
      const start = Math.max(0, index - 60);
      const end = Math.min(domText.length, index + query.length + 60);
      evidence.push({ item, snippet: domText.slice(start, end) });
      occurrences += 1;
      index = lowerText.indexOf(query, index + query.length);
    }
  }
  return evidence;
};

export const resolveIgnoreRobotsTxt = (planState?: unknown): boolean => {
  if (planState === undefined || planState === null) return false;
  try {
    const parsed = (typeof planState === 'string' ? JSON.parse(planState) : planState) as {
      config?: { ignoreRobotsTxt?: boolean };
      ignoreRobotsTxt?: boolean;
    } | null;
    return (parsed?.config?.ignoreRobotsTxt ?? parsed?.ignoreRobotsTxt ?? false);
  } catch (error) {
    logClientError(error);
    return false;
  }
};
